export default ApiKeyModal;

import { AspectRatio, Resolution, GenerationMode, ApiCredentials, MotionStrength, ContextRole, CreativePromptResult } from "../types";
import { MODEL_REASONING, MODEL_IMAGE_BASE } from "../constants";

// Helper: Resize and Compress Image to prevent Payload Too Large (413)
export const fileToDataUrl = async (file: File): Promise<string> => {
  return new Promise((resolve, reject) => {
    const reader = new FileReader();
    reader.onload = (event) => {
      const img = new Image();
      img.onload = () => {
        const canvas = document.createElement('canvas');
        let width = img.width;
        let height = img.height;

        // Resize logic: Max dimension 1024px (Optimal for LLM Vision)
        const MAX_SIZE = 1024; 

        if (width > height) {
          if (width > MAX_SIZE) {
            height *= MAX_SIZE / width;
            width = MAX_SIZE;
          }
        } else {
          if (height > MAX_SIZE) {
            width *= MAX_SIZE / height;
            height = MAX_SIZE;
          }
        }

        canvas.width = width;
        canvas.height = height;
        const ctx = canvas.getContext('2d');

        // Draw white background (for transparent PNGs)
        if (ctx) {
            ctx.fillStyle = "#FFFFFF";
            ctx.fillRect(0, 0, width, height);
            ctx.drawImage(img, 0, 0, width, height);

            // Compress to JPEG quality 0.8 (Significant size reduction vs raw PNG)
            const dataUrl = canvas.toDataURL('image/jpeg', 0.8);
            resolve(dataUrl);
        } else {
            reject(new Error("Canvas Context Error"));
        }
      };
      img.onerror = (err) => reject(new Error("Lỗi đọc file ảnh (Corrupted Image)"));
      img.src = event.target?.result as string;
    };
    reader.onerror = reject;
    reader.readAsDataURL(file);
  });
};

const handleFetchError = (error: unknown, baseUrl: string) => {
    const msg = error instanceof Error ? error.message : String(error);

    // Specific handler for 413 Payload Too Large
    if (msg.includes("413")) {
        throw new Error(`Lỗi 413 (Payload Too Large): Tổng dung lượng ảnh quá lớn. Hệ thống đã tự động nén nhưng Server vẫn từ chối. Vui lòng giảm bớt số lượng ảnh hoặc dùng ảnh nhỏ hơn.`);
    }

    if (msg.includes("Failed to fetch") || msg.includes("NetworkError")) {
        if (window.location.protocol === 'https:' && baseUrl.startsWith('http://')) {
            throw new Error(`Lỗi kết nối (Mixed Content): Trình duyệt chặn gọi HTTP API từ trang HTTPS. Vui lòng dùng Ngrok (HTTPS) hoặc chạy App ở localhost.`);
        }
        throw new Error(`Lỗi kết nối đến Server (${baseUrl}). Vui lòng kiểm tra CORS hoặc Server có đang chạy không.`);
    }
    throw error;
};

// Helper: Convert "16:9" to "16x9" for Banana Pro model naming
const getBananaRatio = (ratio: AspectRatio): string => {
    return ratio.replace(':', 'x');
};

// Helper: Construct Model Name based on Banana Pro Guide
const getBananaModelName = (res: Resolution, ratio: AspectRatio): string => {
    const r = getBananaRatio(ratio);
    if (res === Resolution.RES_1K) {
        return `${MODEL_IMAGE_BASE}-${r}`;
    }
    const resString = res.toLowerCase();
    return `${MODEL_IMAGE_BASE}-${resString}-${r}`;
};

// Helper: Extract URL from Markdown/Text response
const extractUrlFromText = (text: string): string => {
    const markdownRegex = /!\[.*?\]\((.*?)\)/;
    const mdMatch = text.match(markdownRegex);
    if (mdMatch && mdMatch[1]) return mdMatch[1];

    const urlRegex = /(https?:\/\/[^\s)"]+)/g;
    const matches = text.match(urlRegex);

    if (matches && matches.length > 0) {
        let url = matches[0];
        url = url.replace(/[).,;]+$/, "");
        return url;
    }
    return "";
};

// Helper: Robust JSON Cleaning and Parsing
const cleanJsonString = (str: string): string => {
    if (!str) return "{}";

    // 1. Remove Markdown code blocks
    let clean = str.replace(/```json/g, "").replace(/```/g, "").trim();

    // 2. Extract JSON object if embedded in text
    const firstOpen = clean.indexOf('{');
    const lastClose = clean.lastIndexOf('}');

    if (firstOpen !== -1 && lastClose !== -1) {
        clean = clean.substring(firstOpen, lastClose + 1);
    }

    return clean;
};

// Helper: Generic API Caller for OpenAI Format
const callOpenAiApi = async (creds: ApiCredentials, model: string, messages: any[]) => {
    const response = await fetch(`${creds.baseUrl}/chat/completions`, {
        method: 'POST',
        headers: {
            'Content-Type': 'application/json',
            'Authorization': `Bearer ${creds.apiKey}`
        },
        body: JSON.stringify({
            model: model,
            messages: messages,
            max_tokens: 8192, // Gemini Flash supports very large output
            temperature: 0.9  // Higher creativity for Flash
        }),
    });

    if (!response.ok) {
        const text = await response.text();
        throw new Error(`API Error ${response.status}: ${text}`);
    }
    return await response.json();
};

/**
 * Step 1: VISUAL DNA EXTRACTION & DIRECTOR AGENT
 * (Reasoning - Text Generation)
 */
export const enhancePromptWithMotion = async (
  creds: ApiCredentials,
  prompt: string,
  duration: number,
  mode: GenerationMode,
  referenceImageDataUrl: string,
  contextImages: { url: string; role: ContextRole }[] = []
): Promise<string> => {

  const isForward = mode === GenerationMode.FIRST_TO_LAST;
  const targetFrameName = isForward ? 'LAST FRAME' : 'FIRST FRAME';
  const inputFrameName = isForward ? 'FIRST FRAME' : 'LAST FRAME';

  const systemInstruction = `You are an expert AI Video Director.
  CONTEXT: Input Image is ${inputFrameName}. Intent: "${prompt}". Duration: ${duration}s.
  VISUAL REF: Analyze the provided images for Face, Outfit, Style.
  TASK: Write a visual prompt for the ${targetFrameName}.
  OUTPUT: Only the prompt text. No explanations.`;

  // 1. Construct Multimodal Payload
  const userContentMultimodal: any[] = [
    { type: "text", text: `MAIN REFERENCE (${inputFrameName}):` },
    { 
        type: "image_url", 
        image_url: { 
            url: referenceImageDataUrl,
            detail: "low" // Optimization: Use low detail to prevent payload issues/syntax errors on some proxies
        } 
    }
  ];

  if (contextImages.length > 0) {
    userContentMultimodal.push({ type: "text", text: "--- CONTEXT IMAGES ---" });
    contextImages.forEach((img) => {
        userContentMultimodal.push({ type: "text", text: `[${img.role.toUpperCase()}]` });
        userContentMultimodal.push({ 
            type: "image_url", 
            image_url: { 
                url: img.url,
                detail: "low" 
            } 
        });
    });
  }
  userContentMultimodal.push({ type: "text", text: `ACTION: "${prompt}"\nTarget: ${targetFrameName}.` });

  // 2. Construct Text-Only Payload (Fallback)
  const userContentTextOnly = `MAIN REFERENCE: (Image Provided separately)\nACTION: "${prompt}"\nTarget: ${targetFrameName}.`;

  try {
    // ATTEMPT 1: Try with Images
    const data = await callOpenAiApi(creds, MODEL_REASONING, [
        { role: "system", content: systemInstruction }, 
        { role: "user", content: userContentMultimodal }
    ]);

    let content = data.choices?.[0]?.message?.content || prompt;
    if (content.startsWith('"') && content.endsWith('"')) content = content.slice(1, -1);
    return content;

  } catch (error) {
    const errString = String(error);
    console.warn("Director Agent: Multimodal failed, falling back to text-only.", errString);

    // ATTEMPT 2: Fallback to Text Only if Image Syntax/Size fails (400 or 413)
    if (errString.includes("400") || errString.includes("413") || errString.includes("422")) {
        try {
            const data = await callOpenAiApi(creds, MODEL_REASONING, [
                { role: "system", content: systemInstruction }, 
                { role: "user", content: userContentTextOnly }
            ]);
            let content = data.choices?.[0]?.message?.content || prompt;
            if (content.startsWith('"') && content.endsWith('"')) content = content.slice(1, -1);
            return content;
        } catch (retryError) {
             console.error("Director Agent: Text-only fallback also failed.", retryError);
             return prompt; // Return original prompt if everything fails
        }
    }

    return prompt; 
  }
};

/**
 * Step 2: GENERATE VIDEO FRAME (Director Mode)
 */
export const generateVideoFrame = async (
  creds: ApiCredentials,
  enhancedPrompt: string,
  aspectRatio: AspectRatio,
  resolution: Resolution,
  referenceImageDataUrl: string, 
  motionStrength: MotionStrength,
  contextImageDataUrls: string[] = []
): Promise<string> => {

  try {
    const modelName = getBananaModelName(resolution, aspectRatio);
    const contentParts: any[] = [];

    // 1. Add Reference Images FIRST
    contentParts.push({ 
        type: "image_url", 
        image_url: { 
            url: referenceImageDataUrl,
            detail: "low" 
        } 
    });

    contextImageDataUrls.forEach(url => {
        contentParts.push({ 
            type: "image_url", 
            image_url: { 
                url,
                detail: "low"
            } 
        });
    });

    // 2. Add Logic for Motion Strength
    let motionInstruction = "";
    switch (motionStrength) {
        case MotionStrength.LOW:
            motionInstruction = "Changes should be subtle and minimal. Keep composition very close to original.";
            break;
        case MotionStrength.MEDIUM:
            motionInstruction = "Create a natural progression. Moderate movement.";
            break;
        case MotionStrength.HIGH:
            motionInstruction = "Dynamic movement. Significant evolution from the first frame while keeping identity.";
            break;
    }

    // 3. Add Text Prompt LAST
    const finalPrompt = `${enhancedPrompt}\n\n[Motion Strength: ${motionStrength.toUpperCase()} - ${motionInstruction}]`;
    contentParts.push({ type: "text", text: finalPrompt });

    const messages = [{ role: "user", content: contentParts }];

    // Note: Generation models usually MUST have the image if it's image-to-image. 
    // We do NOT fallback to text-only here because that would defeat the purpose of "First Frame".
    const data = await callOpenAiApi(creds, modelName, messages);

    const content = data.choices?.[0]?.message?.content || "";
    const imageUrl = extractUrlFromText(content);

    if (imageUrl) return imageUrl;
    if (content.startsWith("http")) return content;

    console.error("No URL found in response:", content);
    throw new Error("AI đã trả về phản hồi nhưng không tìm thấy đường link ảnh.");

  } catch (error) {
    console.error("Director Gen Error:", error);
    handleFetchError(error, creds.baseUrl);
    throw error;
  }
};

/**
 * OPTIMIZE PROMPT (Creative Mode)
 */
export const optimizeCreativePrompt = async (
    creds: ApiCredentials,
    userPrompt: string,
    imageUrls: string[] = [] 
): Promise<CreativePromptResult> => {
    const systemInstruction = `You are an AI Art Prompt Engineer.
    TASK: Optimize the User's Idea based on the provided Reference Images.

    CRITICAL GUIDELINES:
    1. COLOR FIDELITY: Do NOT add artistic filters, color grading (e.g., 'cinematic lighting', 'warm tone', 'teal and orange', 'vibrant'), or lighting effects unless the User explicitly asks for them.
    2. PRESERVE ORIGINALITY: If the user does not specify a color scheme, you MUST maintain the original color palette, lighting, and texture of the Reference Images.
    3. DESCRIPTIVE: Focus on describing the subjects, action, and composition.

    OUTPUT FORMAT: Strictly JSON. Do not output markdown.
    Structure: { "english": "string", "vietnamese": "string" }`;

    // 1. Construct Multimodal Payload
    const userContentMultimodal: any[] = [{ type: "text", text: `Idea: "${userPrompt}"` }];
    imageUrls.forEach(url => userContentMultimodal.push({ 
        type: "image_url", 
        image_url: { 
            url, 
            detail: "low" // Optimization for syntax/size
        } 
    }));

    // 2. Construct Text-Only Payload (Fallback)
    const userContentTextOnly = [{ type: "text", text: `Idea: "${userPrompt}" (Analyze text only, ignore images for this step)` }];

    try {
        // ATTEMPT 1: Multimodal
        const data = await callOpenAiApi(creds, MODEL_REASONING, [
            { role: "system", content: systemInstruction }, 
            { role: "user", content: userContentMultimodal }
        ]);

        const content = data.choices?.[0]?.message?.content || "{}";
        const cleanContent = cleanJsonString(content);
        return JSON.parse(cleanContent);

    } catch (e) {
        const errString = String(e);
        console.warn("Creative Optimizer: Multimodal failed, falling back to text-only.", errString);

        // ATTEMPT 2: Fallback to Text Only
        if (errString.includes("400") || errString.includes("413") || errString.includes("422")) {
             try {
                const data = await callOpenAiApi(creds, MODEL_REASONING, [
                    { role: "system", content: systemInstruction }, 
                    { role: "user", content: userContentTextOnly }
                ]);
                const content = data.choices?.[0]?.message?.content || "{}";
                const cleanContent = cleanJsonString(content);
                return JSON.parse(cleanContent);
             } catch (retryEx) {
                 // Final Fail
                 return { english: userPrompt, vietnamese: "Lỗi tối ưu (AI không trả về đúng định dạng JSON hoặc Lỗi Mạng), dùng prompt gốc." };
             }
        }

        handleFetchError(e, creds.baseUrl);
        return { english: userPrompt, vietnamese: "Lỗi tối ưu, dùng prompt gốc." };
    }
};

/**
 * GENERATE IMAGE FOR CREATIVE MODE
 */
export const generateCreativeImage = async (
    creds: ApiCredentials,
    prompt: string,
    aspectRatio: AspectRatio,
    resolution: Resolution,
    referenceImagesDataUrls: string[]
): Promise<string> => {

    try {
        const modelName = getBananaModelName(resolution, aspectRatio);
        const contentParts: any[] = [];

        // 1. Add Images FIRST
        referenceImagesDataUrls.forEach(url => {
            contentParts.push({ 
                type: "image_url", 
                image_url: { 
                    url,
                    detail: "low"
                } 
            });
        });

        // 2. Add Text Prompt LAST
        contentParts.push({ type: "text", text: prompt });

        const messages = [{ role: "user", content: contentParts }];
        const data = await callOpenAiApi(creds, modelName, messages);

        const content = data.choices?.[0]?.message?.content || "";
        const imageUrl = extractUrlFromText(content);

        if (imageUrl) return imageUrl;

        if (content.length > 1000 && !content.includes(" ")) {
            return `data:image/png;base64,${content}`;
        }

        if (content.startsWith("http")) return content;

        console.error("Response content:", content);
        throw new Error("Không tìm thấy link ảnh trong phản hồi của AI.");

    } catch (error) {
        console.error("Creative Gen Error:", error);
        handleFetchError(error, creds.baseUrl);
        throw error;
    }
};

