    if (mdMatch && mdMatch[1]) return mdMatch[1];

    const urlRegex = /(https?:\/\/[^\s)"]+)/g;
    const matches = text.match(urlRegex);

    if (matches && matches.length > 0) {
        let url = matches[0];
        url = url.replace(/[).,;]+$/, "");
        return url;
    }
    return "";
};

// Helper: Robust JSON Cleaning and Parsing
const cleanJsonString = (str: string): string => {
    if (!str) return "{}";

    // 1. Remove Markdown code blocks
    let clean = str.replace(/```json/g, "").replace(/```/g, "").trim();

    // 2. Extract JSON object if embedded in text
    const firstOpen = clean.indexOf('{');
    const lastClose = clean.lastIndexOf('}');

    if (firstOpen !== -1 && lastClose !== -1) {
        clean = clean.substring(firstOpen, lastClose + 1);
    }

    return clean;
};

/**
 * SMART API CALLER FOR BANANA PRO
 * Handles Port Switching (8045 <-> 8046) automatically
 */
const callOpenAiApi = async (creds: ApiCredentials, model: string, messages: any[]) => {
    let finalUrl = `${creds.baseUrl}/chat/completions`;

    // --- SMART PORT SWITCHING LOGIC ---
    // If running on localhost/127.0.0.1, we assume standard Banana Pro config:
    // Port 8045: Text/Flash/Reasoning
    // Port 8046: Image Generation

    if (creds.baseUrl.includes('localhost') || creds.baseUrl.includes('127.0.0.1')) {
        const isImageModel = model.startsWith(MODEL_IMAGE_BASE); // gemini-3-pro-image...
        const isFlashModel = model.includes('flash');            // gemini-3-flash

        // If requesting Image Model but URL is on Port 8045 -> Switch to 8046
        if (isImageModel && creds.baseUrl.includes(':8045')) {
            finalUrl = finalUrl.replace(':8045', ':8046');
            console.log(`[Smart Switch] Routing Image Request to Port 8046`);
        }

        // If requesting Flash Model but URL is on Port 8046 -> Switch to 8045
        else if (isFlashModel && creds.baseUrl.includes(':8046')) {
            finalUrl = finalUrl.replace(':8046', ':8045');
            console.log(`[Smart Switch] Routing Flash Request to Port 8045`);
        }
    }
    // ----------------------------------

    const response = await fetch(finalUrl, {
        method: 'POST',
        headers: {
            'Content-Type': 'application/json',
            'Authorization': `Bearer ${creds.apiKey}`
        },
        body: JSON.stringify({
            model: model,
            messages: messages,
            max_tokens: 8192, // Gemini Flash supports very large output
            temperature: 0.9  // Higher creativity
        }),
    });

    if (!response.ok) {
        const text = await response.text();
        throw new Error(`API Error ${response.status} at ${finalUrl}: ${text}`);
    }
    return await response.json();
};

/**
 * Step 1: VISUAL DNA EXTRACTION & DIRECTOR AGENT
 * Model: Gemini 3 Flash (Port 8045)
 */
export const enhancePromptWithMotion = async (
  creds: ApiCredentials,
  prompt: string,
  duration: number,
  mode: GenerationMode,
  referenceImageDataUrl: string,
  contextImages: { url: string; role: ContextRole }[] = []
): Promise<string> => {

  const isForward = mode === GenerationMode.FIRST_TO_LAST;
  const targetFrameName = isForward ? 'LAST FRAME' : 'FIRST FRAME';
  const inputFrameName = isForward ? 'FIRST FRAME' : 'LAST FRAME';

  // Strict System Instruction for Director Mode
  const systemInstruction = `You are an expert AI Video Director.
  CONTEXT:
  - Input Image: ${inputFrameName} of a video shot.
  - Duration: ${duration} seconds.
  - User Intent: "${prompt}"

  VISUAL ANALYSIS TASK:
  1. Carefully analyze the "MAIN REFERENCE" image for character identity, outfit, and setting.
  2. Analyze "CONTEXT IMAGES" (if any) to understand specific details (Face, Background, Style).
  3. IMAGINE the motion occurring over ${duration} seconds based on the Intent.

  OUTPUT TASK:
  Write a highly descriptive visual prompt for the ${targetFrameName}.
  - Describe the SUBJECT'S new pose/expression.
  - Describe the CAMERA movement (if implied).
  - Describe the BACKGROUND changes (if any).
  - KEEP IT CONCISE but visually rich.

  OUTPUT FORMAT: Just the prompt text. No "Here is the prompt" prefix.`;

  // 1. Construct Multimodal Payload
  const userContentMultimodal: any[] = [
    { type: "text", text: `MAIN REFERENCE (${inputFrameName}):` },
    { 
        type: "image_url", 
        image_url: { 
            url: referenceImageDataUrl,
            detail: "low" // 'low' is faster and sufficient for Flash reasoning
        } 
    }
  ];

  if (contextImages.length > 0) {
    userContentMultimodal.push({ type: "text", text: "--- ADDITIONAL CONTEXT IMAGES ---" });
    contextImages.forEach((img) => {
        userContentMultimodal.push({ type: "text", text: `[${img.role.toUpperCase()}]` });
        userContentMultimodal.push({ 
            type: "image_url", 
            image_url: { 
                url: img.url,
                detail: "low" 
            } 
        });
    });
  }
  userContentMultimodal.push({ type: "text", text: `ACTION INTENT: "${prompt}"\nTask: Describe the ${targetFrameName}.` });

  // 2. Construct Text-Only Payload (Fallback)
  const userContentTextOnly = `MAIN REFERENCE: (Image Provided separately)\nACTION: "${prompt}"\nTarget: ${targetFrameName}.`;

  try {
    // ATTEMPT 1: Try with Images (Multimodal)
    const data = await callOpenAiApi(creds, MODEL_REASONING, [
        { role: "system", content: systemInstruction }, 
        { role: "user", content: userContentMultimodal }
    ]);

    let content = data.choices?.[0]?.message?.content || prompt;
    if (content.startsWith('"') && content.endsWith('"')) content = content.slice(1, -1);
    return content;

  } catch (error) {
    const errString = String(error);
    console.warn("Director Agent: Multimodal failed, falling back to text-only.", errString);

    // ATTEMPT 2: Fallback to Text Only
    if (errString.includes("400") || errString.includes("413") || errString.includes("422")) {
        try {
            const data = await callOpenAiApi(creds, MODEL_REASONING, [
                { role: "system", content: systemInstruction }, 
                { role: "user", content: userContentTextOnly }
            ]);
            let content = data.choices?.[0]?.message?.content || prompt;
            if (content.startsWith('"') && content.endsWith('"')) content = content.slice(1, -1);
            return content;
        } catch (retryError) {
             return prompt; // Return original prompt if everything fails
        }
    }

    return prompt; 
  }
};

