// Helper: Resize and Compress Image to prevent Payload Too Large (413)
export const fileToDataUrl = async (file: File): Promise<string> => {
  return new Promise((resolve, reject) => {
    const reader = new FileReader();
    reader.onload = (event) => {
      const img = new Image();
      img.onload = () => {
        const canvas = document.createElement('canvas');
        let width = img.width;
        let height = img.height;

        // Resize logic: Max dimension 1024px (Optimal for LLM Vision)
        const MAX_SIZE = 1024; 

        if (width > height) {
          if (width > MAX_SIZE) {
            height *= MAX_SIZE / width;
            width = MAX_SIZE;
          }
        } else {
          if (height > MAX_SIZE) {
            width *= MAX_SIZE / height;
            height = MAX_SIZE;
          }
        }

        canvas.width = width;
        canvas.height = height;
        const ctx = canvas.getContext('2d');

        // Draw white background (for transparent PNGs)
        if (ctx) {
            ctx.fillStyle = "#FFFFFF";
            ctx.fillRect(0, 0, width, height);
            ctx.drawImage(img, 0, 0, width, height);

            // Compress to JPEG quality 0.8 (Significant size reduction vs raw PNG)
            const dataUrl = canvas.toDataURL('image/jpeg', 0.8);
            resolve(dataUrl);
        } else {
            reject(new Error("Canvas Context Error"));
        }
      };
      img.onerror = (err) => reject(new Error("Lỗi đọc file ảnh (Corrupted Image)"));
      img.src = event.target?.result as string;
    };
    reader.onerror = reject;
    reader.readAsDataURL(file);
  });
};

const handleFetchError = (error: unknown, baseUrl: string) => {
    const msg = error instanceof Error ? error.message : String(error);

    // Specific handler for 413 Payload Too Large
    if (msg.includes("413")) {
        throw new Error(`Lỗi 413 (Payload Too Large): Tổng dung lượng ảnh quá lớn. Vui lòng giảm bớt số lượng ảnh hoặc dùng ảnh nhỏ hơn.`);
    }

    if (msg.includes("Failed to fetch") || msg.includes("NetworkError")) {
        if (window.location.protocol === 'https:' && baseUrl.startsWith('http://')) {
            throw new Error(`Lỗi kết nối (Mixed Content): App chạy HTTPS không thể gọi HTTP Localhost. Vui lòng dùng Ngrok hoặc chạy App ở Localhost.`);
        }
        throw new Error(`Lỗi kết nối đến Server (${baseUrl}). Vui lòng kiểm tra xem Server có đang chạy ở Port này không.`);
    }
    throw error;
};

// Helper: Convert "16:9" to "16x9" for Banana Pro model naming
const getBananaRatio = (ratio: AspectRatio): string => {
    return ratio.replace(':', 'x');
};

// Helper: Construct Model Name based on Banana Pro Guide
const getBananaModelName = (res: Resolution, ratio: AspectRatio): string => {
    const r = getBananaRatio(ratio);
    if (res === Resolution.RES_1K) {
        return `${MODEL_IMAGE_BASE}-${r}`;
    }
    const resString = res.toLowerCase();
    return `${MODEL_IMAGE_BASE}-${resString}-${r}`;
};

// Helper: Extract URL from Markdown/Text response
const extractUrlFromText = (text: string): string => {
    const markdownRegex = /!\[.*?\]\((.*?)\)/;
    const mdMatch = text.match(markdownRegex);
    if (mdMatch && mdMatch[1]) return mdMatch[1];

    const urlRegex = /(https?:\/\/[^\s)"]+)/g;
    const matches = text.match(urlRegex);

    if (matches && matches.length > 0) {
        let url = matches[0];
        url = url.replace(/[).,;]+$/, "");
        return url;
    }
    return "";
};

// Helper: Robust JSON Cleaning and Parsing
const cleanJsonString = (str: string): string => {
    if (!str) return "{}";
    let clean = str.replace(/```json/g, "").replace(/```/g, "").trim();
    const firstOpen = clean.indexOf('{');
    const lastClose = clean.lastIndexOf('}');
    if (firstOpen !== -1 && lastClose !== -1) {
        clean = clean.substring(firstOpen, lastClose + 1);
    }
    return clean;
};

/**
 * SMART API CALLER
 * Respects User's Base URL but handles Localhost Port Quirks (8045 vs 8046)
 */
const callOpenAiApi = async (creds: ApiCredentials, model: string, messages: any[]) => {
    let finalUrl = `${creds.baseUrl}/chat/completions`;

    // Logic: Only tamper with Ports if we detect standard Localhost Banana Pro setup
    const isLocal = creds.baseUrl.includes('localhost') || creds.baseUrl.includes('127.0.0.1');

    if (isLocal) {
        const isImageModel = model.startsWith(MODEL_IMAGE_BASE); // gemini-3-pro-image...
        const isReasoningModel = !isImageModel;                  // gemini-3-flash

        // Scenario 1: User set Base URL to 8045 (Text/Flash default)
        // But we are requesting an Image Generation -> Switch to 8046
        if (isImageModel && creds.baseUrl.includes(':8045')) {
            finalUrl = finalUrl.replace(':8045', ':8046');
        }

        // Scenario 2: User set Base URL to 8046 (Image default)
        // But we are requesting Reasoning/Scripting -> Switch to 8045
        else if (isReasoningModel && creds.baseUrl.includes(':8046')) {
            finalUrl = finalUrl.replace(':8046', ':8045');
        }
    }

    const response = await fetch(finalUrl, {
        method: 'POST',
        headers: {
            'Content-Type': 'application/json',
            'Authorization': `Bearer ${creds.apiKey}`
        },
        body: JSON.stringify({
            model: model,
            messages: messages,
            max_tokens: 8192, // Gemini Flash Supports Large Context
            temperature: 0.9, // High creativity
            stream: false
        }),
    });

    if (!response.ok) {
        const text = await response.text();
        throw new Error(`API Error ${response.status} (${model}): ${text}`);
    }
    return await response.json();
};

/**
 * FEATURE 1: LÊN KỊCH BẢN (Director Mode)
 * Model: Gemini 3 Flash
 * Input: Ảnh gốc + Ảnh ngữ cảnh + Prompt
 */
export const enhancePromptWithMotion = async (
  creds: ApiCredentials,
  prompt: string,
  duration: number,
  mode: GenerationMode,
  referenceImageDataUrl: string,
  contextImages: { url: string; role: ContextRole }[] = []
): Promise<string> => {

  const isForward = mode === GenerationMode.FIRST_TO_LAST;
  const targetFrameName = isForward ? 'LAST FRAME' : 'FIRST FRAME';
  const inputFrameName = isForward ? 'FIRST FRAME' : 'LAST FRAME';

  // Prompt tối ưu cho Flash để đóng vai Đạo Diễn
  const systemInstruction = `You are a visionary AI Film Director.
  GOAL: Describe the ${targetFrameName} of a shot, based on the ${inputFrameName} and the User's Action Intent.

  INPUTS:
  1. MAIN IMAGE: The ${inputFrameName}. Maintain the character identity and setting implicitly.
  2. CONTEXT IMAGES: Use these for specific details (e.g., if a 'Face' image is provided, ensure facial features match).
  3. INTENT: "${prompt}" (The action happening over ${duration} seconds).

  OUTPUT:
  Write a vivid, visual prompt for the ${targetFrameName}.
  - Focus on the RESULT of the action.
  - Describe the change in Pose, Expression, and Camera Angle.
  - If the action implies a new background, describe it.
  - FORMAT: Raw prompt string only. No explanations.`;

  const userContentMultimodal: any[] = [
    { type: "text", text: `[MAIN REFERENCE IMAGE - ${inputFrameName}]` },
    { type: "image_url", image_url: { url: referenceImageDataUrl, detail: "low" } }
  ];

  if (contextImages.length > 0) {
    userContentMultimodal.push({ type: "text", text: "[ADDITIONAL CONTEXT / STYLE GUIDES]" });
    contextImages.forEach((img) => {
        userContentMultimodal.push({ type: "text", text: `Role: ${img.role.toUpperCase()}` });
        userContentMultimodal.push({ type: "image_url", image_url: { url: img.url, detail: "low" } });
    });
  }
  userContentMultimodal.push({ type: "text", text: `USER INTENT: "${prompt}"\nGENERATE ${targetFrameName} PROMPT.` });

  // Fallback text-only payload
  const userContentTextOnly = `Task: Create a visual prompt for the ${targetFrameName} where the subject performs: "${prompt}". Duration: ${duration}s.`;

  try {
    const data = await callOpenAiApi(creds, MODEL_REASONING, [
        { role: "system", content: systemInstruction }, 
        { role: "user", content: userContentMultimodal }
    ]);

    let content = data.choices?.[0]?.message?.content || prompt;
    if (content.startsWith('"') && content.endsWith('"')) content = content.slice(1, -1);
    return content;

  } catch (error) {
    const errString = String(error);
    // Nếu lỗi do gửi ảnh (400/413/422), thử lại bằng text-only
    if (errString.includes("400") || errString.includes("413") || errString.includes("422")) {
        try {
            const data = await callOpenAiApi(creds, MODEL_REASONING, [
                { role: "system", content: systemInstruction }, 
                { role: "user", content: userContentTextOnly }
            ]);
            let content = data.choices?.[0]?.message?.content || prompt;
            if (content.startsWith('"') && content.endsWith('"')) content = content.slice(1, -1);
            return content;
        } catch (retryError) {
             return prompt;
        }
    }
    return prompt; 
  }
};

