// Helper: Resize and Compress Image
export const fileToDataUrl = async (file: File): Promise<string> => {
  return new Promise((resolve, reject) => {
    const reader = new FileReader();
    reader.onload = (event) => {
      const img = new Image();
      img.onload = () => {
        const canvas = document.createElement('canvas');
        let width = img.width;
        let height = img.height;
        const MAX_SIZE = 1024; 

        if (width > height) {
          if (width > MAX_SIZE) {
            height *= MAX_SIZE / width;
            width = MAX_SIZE;
          }
        } else {
          if (height > MAX_SIZE) {
            width *= MAX_SIZE / height;
            height = MAX_SIZE;
          }
        }

        canvas.width = width;
        canvas.height = height;
        const ctx = canvas.getContext('2d');

        if (ctx) {
            ctx.fillStyle = "#FFFFFF";
            ctx.fillRect(0, 0, width, height);
            ctx.drawImage(img, 0, 0, width, height);
            const dataUrl = canvas.toDataURL('image/jpeg', 0.8);
            resolve(dataUrl);
        } else {
            reject(new Error("Canvas Context Error"));
        }
      };
      img.onerror = () => reject(new Error("Lỗi đọc file ảnh"));
      img.src = event.target?.result as string;
    };
    reader.onerror = reject;
    reader.readAsDataURL(file);
  });
};

const handleFetchError = (error: unknown, baseUrl: string) => {
    const msg = error instanceof Error ? error.message : String(error);
    if (msg.includes("413")) {
        throw new Error(`Lỗi 413: Ảnh quá lớn. Hãy giảm dung lượng.`);
    }
    if (msg.includes("Failed to fetch") || msg.includes("NetworkError")) {
        if (window.location.protocol === 'https:' && baseUrl.startsWith('http://')) {
            throw new Error(`Lỗi Mixed Content: App HTTPS không gọi được API HTTP. Hãy dùng link Cloudflare/Ngrok HTTPS.`);
        }
        throw new Error(`Không thể kết nối đến ${baseUrl}. Kiểm tra Server Banana Pro.`);
    }
    throw error;
};

// Banana Pro Model Name helper
const getBananaModelName = (res: Resolution, ratio: AspectRatio): string => {
    const r = ratio.replace(':', 'x');
    if (res === Resolution.RES_1K) {
        return `${MODEL_IMAGE_BASE}-${r}`;
    }
    const resString = res.toLowerCase();
    return `${MODEL_IMAGE_BASE}-${resString}-${r}`;
};

const extractUrlFromText = (text: string): string => {
    const markdownRegex = /!\[.*?\]\((.*?)\)/;
    const mdMatch = text.match(markdownRegex);
    if (mdMatch && mdMatch[1]) return mdMatch[1];

    const urlRegex = /(https?:\/\/[^\s)"]+)/g;
    const matches = text.match(urlRegex);

    if (matches && matches.length > 0) {
        let url = matches[0];
        url = url.replace(/[).,;]+$/, "");
        return url;
    }
    return "";
};

const cleanJsonString = (str: string): string => {
    if (!str) return "{}";
    let clean = str.replace(/```json/g, "").replace(/```/g, "").trim();
    const firstOpen = clean.indexOf('{');
    const lastClose = clean.lastIndexOf('}');
    if (firstOpen !== -1 && lastClose !== -1) {
        clean = clean.substring(firstOpen, lastClose + 1);
    }
    return clean;
};

/**
 * STANDARD API CALLER
 * Strictly uses the User Provided Base URL (No magic port switching).
 */
const callOpenAiApi = async (creds: ApiCredentials, model: string, messages: any[]) => {
    const baseUrl = creds.baseUrl.endsWith('/') ? creds.baseUrl.slice(0, -1) : creds.baseUrl;
    const finalUrl = `${baseUrl}/chat/completions`;

    const response = await fetch(finalUrl, {
        method: 'POST',
        headers: {
            'Content-Type': 'application/json',
            'Authorization': `Bearer ${creds.apiKey}`
        },
        body: JSON.stringify({
            model: model,
            messages: messages,
            max_tokens: 8192,
            temperature: 0.9,
            stream: false
        }),
    });

    if (!response.ok) {
        const text = await response.text();
        throw new Error(`API Error ${response.status} (${model}): ${text}`);
    }
    return await response.json();
};

/**
 * FEATURE 1: LÊN KỊCH BẢN (Director Mode)
 * Model: Gemini 3 Flash (MODEL_REASONING)
 * Input: Ảnh gốc (Main) + Ảnh ngữ cảnh (Context) + Prompt
 */
export const enhancePromptWithMotion = async (
  creds: ApiCredentials,
  prompt: string,
  duration: number,
  mode: GenerationMode,
  referenceImageDataUrl: string,
  contextImages: { url: string; role: ContextRole }[] = []
): Promise<string> => {

  const isForward = mode === GenerationMode.FIRST_TO_LAST;
  const targetFrameName = isForward ? 'LAST FRAME' : 'FIRST FRAME';
  const inputFrameName = isForward ? 'FIRST FRAME' : 'LAST FRAME';

  // System Prompt được tối ưu cho việc "Hiểu ngữ cảnh"
  const systemInstruction = `You are a visionary AI Film Director.
  GOAL: Describe the ${targetFrameName} of a shot.

  INPUT ANALYSIS:
  1. MAIN IMAGE: This is the ${inputFrameName}. Keep the character and setting consistent with this.
  2. CONTEXT IMAGES (Important): Use these for extra details.
     - If 'Face' is provided, ensure facial features match strictly.
     - If 'Background' is provided, ensure the environment matches.
     - If 'Outfit' is provided, apply it to the character.
  3. INTENT: "${prompt}" (Action over ${duration}s).

  OUTPUT:
  Write a vivid, visual prompt for the ${targetFrameName}.
  - Describe the visual result of the action.
  - Describe camera movement and angle.
  - FORMAT: Raw prompt string only.`;

  const userContentMultimodal: any[] = [
    { type: "text", text: `[MAIN REFERENCE IMAGE - ${inputFrameName}]` },
    { type: "image_url", image_url: { url: referenceImageDataUrl, detail: "low" } }
  ];

  if (contextImages.length > 0) {
    userContentMultimodal.push({ type: "text", text: "[ADDITIONAL CONTEXT / STYLE GUIDES]" });
    contextImages.forEach((img) => {
        userContentMultimodal.push({ type: "text", text: `Role: ${img.role.toUpperCase()}` });
        userContentMultimodal.push({ type: "image_url", image_url: { url: img.url, detail: "low" } });
    });
  }
  userContentMultimodal.push({ type: "text", text: `USER INTENT: "${prompt}"\nTask: Generate ${targetFrameName} Prompt.` });

  // Fallback text-only
  const userContentTextOnly = `Task: Create a visual prompt for the ${targetFrameName} where the subject performs: "${prompt}". Duration: ${duration}s.`;

  try {
    const data = await callOpenAiApi(creds, MODEL_REASONING, [
        { role: "system", content: systemInstruction }, 
        { role: "user", content: userContentMultimodal }
    ]);

    let content = data.choices?.[0]?.message?.content || prompt;
    if (content.startsWith('"') && content.endsWith('"')) content = content.slice(1, -1);
    return content;

  } catch (error) {
    const errString = String(error);
    if (errString.includes("400") || errString.includes("413") || errString.includes("422")) {
        try {
            const data = await callOpenAiApi(creds, MODEL_REASONING, [
                { role: "system", content: systemInstruction }, 
                { role: "user", content: userContentTextOnly }
            ]);
            let content = data.choices?.[0]?.message?.content || prompt;
            if (content.startsWith('"') && content.endsWith('"')) content = content.slice(1, -1);
            return content;
        } catch (retryError) {
             return prompt;
        }
    }
    return prompt; 
  }
};

/**
 * FEATURE 2: TẠO ẢNH VIDEO (Director Gen)
 * Model: Gemini 3 Pro Image (MODEL_IMAGE_BASE)
 * Input: Nhiều hình tham chiếu (Ảnh gốc + Ảnh ngữ cảnh) + Text
 */
export const generateVideoFrame = async (
  creds: ApiCredentials,
  enhancedPrompt: string,
  aspectRatio: AspectRatio,
  resolution: Resolution,
  referenceImageDataUrl: string, 
  motionStrength: MotionStrength,
  contextImageDataUrls: string[] = []
): Promise<string> => {

  try {
    const modelName = getBananaModelName(resolution, aspectRatio);
    const contentParts: any[] = [];

    // 1. Gửi ảnh gốc (First Frame)
    contentParts.push({ 
        type: "image_url", 
        image_url: { url: referenceImageDataUrl, detail: "low" } 
    });

    // 2. Gửi ảnh ngữ cảnh (Style/Face/Bg reference) - Support multi-image inputs
    contextImageDataUrls.forEach(url => {
        contentParts.push({ 
            type: "image_url", 
            image_url: { url, detail: "low" } 
        });
    });

    // 3. Text Prompt
    let motionInstruction = "";
    switch (motionStrength) {
        case MotionStrength.LOW: motionInstruction = "Minimal change."; break;
        case MotionStrength.MEDIUM: motionInstruction = "Natural evolution."; break;
        case MotionStrength.HIGH: motionInstruction = "Dynamic change."; break;
    }

    const finalPrompt = `${enhancedPrompt} . ${motionInstruction}`;
    contentParts.push({ type: "text", text: finalPrompt });

    const messages = [{ role: "user", content: contentParts }];
    const data = await callOpenAiApi(creds, modelName, messages);

    const content = data.choices?.[0]?.message?.content || "";
    const imageUrl = extractUrlFromText(content);

    if (imageUrl) return imageUrl;
    if (content.startsWith("http")) return content;

    throw new Error("AI không trả về link ảnh.");

  } catch (error) {
    handleFetchError(error, creds.baseUrl);
    throw error;
  }
};

/**
 * FEATURE 3: TỐI ƯU PROMPT (Creative Mode)
 * Model: Gemini 3 Flash (MODEL_REASONING)
 * Input: Prompt Text + (Optionally) Reference Images
 */
export const optimizeCreativePrompt = async (
    creds: ApiCredentials,
    userPrompt: string,
    imageUrls: string[] = [] 
): Promise<CreativePromptResult> => {
    const systemInstruction = `You are a Prompt Engineer.
    TASK: Analyze User Idea + Reference Images (if any).
    OUTPUT: A detailed stable-diffusion style prompt.

    GUIDELINES:
    - If images provided: Describe style/lighting/composition and blend with User Idea.
    - If no images: Expand User Idea artistically.
    - No color grading unless requested.

    RETURN JSON: { "english": "...", "vietnamese": "..." }`;

    const userContentMultimodal: any[] = [{ type: "text", text: `USER IDEA: "${userPrompt}"` }];

    // Feature: Tối ưu hoá prompt (có hình tham chiếu hoặc không)
    if (imageUrls.length > 0) {
        userContentMultimodal.push({ type: "text", text: "REFERENCES:" });
        imageUrls.forEach(url => userContentMultimodal.push({ 
            type: "image_url", 
            image_url: { url, detail: "low" } 
        }));
    }

    const userContentTextOnly = [{ type: "text", text: `USER IDEA: "${userPrompt}"` }];

    try {
        const data = await callOpenAiApi(creds, MODEL_REASONING, [
            { role: "system", content: systemInstruction }, 
            { role: "user", content: userContentMultimodal }
        ]);

        const content = data.choices?.[0]?.message?.content || "{}";
        const cleanContent = cleanJsonString(content);
        return JSON.parse(cleanContent);

    } catch (e) {
        try {
            const data = await callOpenAiApi(creds, MODEL_REASONING, [
                { role: "system", content: systemInstruction }, 
                { role: "user", content: userContentTextOnly }
            ]);
            const content = data.choices?.[0]?.message?.content || "{}";
            const cleanContent = cleanJsonString(content);
            return JSON.parse(cleanContent);
        } catch (retryEx) {
             return { english: userPrompt, vietnamese: "Lỗi tối ưu, dùng prompt gốc." };
        }
    }
};

/**
 * FEATURE 4: TẠO ẢNH SÁNG TẠO
 * Model: Gemini 3 Pro Image (MODEL_IMAGE_BASE)
 */
export const generateCreativeImage = async (
    creds: ApiCredentials,
    prompt: string,
    aspectRatio: AspectRatio,
    resolution: Resolution,
    referenceImagesDataUrls: string[]
): Promise<string> => {
    try {
        const modelName = getBananaModelName(resolution, aspectRatio);
        const contentParts: any[] = [];

        // Multi-reference inputs
        referenceImagesDataUrls.forEach(url => {
            contentParts.push({ 
                type: "image_url", 
                image_url: { url, detail: "low" } 
            });
        });

        contentParts.push({ type: "text", text: prompt });

        const messages = [{ role: "user", content: contentParts }];
        const data = await callOpenAiApi(creds, modelName, messages);

        const content = data.choices?.[0]?.message?.content || "";
        const imageUrl = extractUrlFromText(content);

        if (imageUrl) return imageUrl;
        if (content.length > 1000 && !content.includes(" ")) return `data:image/png;base64,${content}`;
        if (content.startsWith("http")) return content;

        throw new Error("Không tìm thấy link ảnh.");

    } catch (error) {
        handleFetchError(error, creds.baseUrl);
        throw error;
    }
};

import React, { useState, useRef } from 'react';
import { AspectRatio, Resolution, GenerationMode, GeneratedImage, ApiCredentials, MotionStrength, ContextImage, ContextRole, AppMode } from './types';
import { ASPECT_RATIOS, RESOLUTIONS } from './constants';
import { fileToDataUrl, enhancePromptWithMotion, generateVideoFrame } from './services/geminiService';
import { Upload, Wand2, Image as ImageIcon, Loader2, PlaySquare, Rewind, FastForward, Download, Settings, Trash2, Plus, XCircle, Minimize2, Move, Video, Zap, FileText, RefreshCw, Copy, Clapperboard, User, Mountain, Palette, Shirt, Sparkles } from 'lucide-react';
import ApiKeyModal from './components/ApiKeyModal';
import ImageViewer from './components/ImageViewer';
import CreativeMode from './components/CreativeMode';

export default function App() {
  const [credentials, setCredentials] = useState<ApiCredentials | null>(null);

  // App Mode State
  const [appMode, setAppMode] = useState<AppMode>(AppMode.DIRECTOR);

  // --- DIRECTOR MODE STATE ---
  const [prompt, setPrompt] = useState('');
  const [duration, setDuration] = useState(5);
  const [aspectRatio, setAspectRatio] = useState<AspectRatio>(AspectRatio.R_16_9);
  const [resolution, setResolution] = useState<Resolution>(Resolution.RES_1K);
  const [generationCount, setGenerationCount] = useState(1);
  const [mode, setMode] = useState<GenerationMode>(GenerationMode.FIRST_TO_LAST);
  const [motionStrength, setMotionStrength] = useState<MotionStrength>(MotionStrength.MEDIUM);

  const [refFile, setRefFile] = useState<File | null>(null);
  const [refPreview, setRefPreview] = useState<string | null>(null);
  const [contextImages, setContextImages] = useState<ContextImage[]>([]);

  const [optimizedPrompt, setOptimizedPrompt] = useState<string>('');
  const [isAnalyzing, setIsAnalyzing] = useState(false);
  const [showScriptEditor, setShowScriptEditor] = useState(false);
  // ---------------------------

  // Shared Output State
  const [isRendering, setIsRendering] = useState(false);
  const [generatingCount, setGeneratingCount] = useState(0); 
  const [statusMessage, setStatusMessage] = useState('');
  const [results, setResults] = useState<GeneratedImage[]>([]);
  const [selectedImageId, setSelectedImageId] = useState<string | null>(null);
  const [showLogin, setShowLogin] = useState(true);

  const refInputRef = useRef<HTMLInputElement>(null);
  const ctxInputRef = useRef<HTMLInputElement>(null);

  const handleCredentials = (creds: ApiCredentials) => {
    setCredentials(creds);
    setShowLogin(false);
  };

  // --- DIRECTOR HANDLERS ---
  const handleRefUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
    if (e.target.files && e.target.files[0]) {
      const file = e.target.files[0];
      setRefFile(file);
      setRefPreview(URL.createObjectURL(file as Blob));
      setOptimizedPrompt('');
      setShowScriptEditor(false);
    }
  };

  const handleCtxUpload = async (e: React.ChangeEvent<HTMLInputElement>) => {
    if (e.target.files && e.target.files.length > 0) {
      const newFiles: File[] = Array.from(e.target.files);
      const newImages: ContextImage[] = newFiles.map(file => ({
        id: Math.random().toString(36).substring(7),
        file,
        preview: URL.createObjectURL(file),
        role: ContextRole.GENERAL 
      }));
      setContextImages(prev => [...prev, ...newImages]);
    }
    if (ctxInputRef.current) ctxInputRef.current.value = '';
  };

  const updateContextRole = (id: string, newRole: ContextRole) => {
    setContextImages(prev => prev.map(img => 
        img.id === id ? { ...img, role: newRole } : img
    ));
  };

  const removeContextImage = (id: string) => {
    setContextImages(prev => prev.filter(img => img.id !== id));
  };

  const handleStopWaiting = () => {
    setIsRendering(false);
    setStatusMessage("Đã ẩn trạng thái chờ. Các ảnh đang tạo sẽ tự động hiện khi hoàn tất (Chạy ngầm).");
  };

  const copyScriptToClipboard = () => {
    navigator.clipboard.writeText(optimizedPrompt);
    setStatusMessage("Đã copy kịch bản vào bộ nhớ đệm!");
    setTimeout(() => setStatusMessage(''), 2000);
  };

  const handleDeleteImage = (id: string) => {
    if (window.confirm("Bạn có chắc chắn muốn xóa ảnh này không?")) {
      setResults(prev => prev.filter(img => img.id !== id));
      if (selectedImageId === id) setSelectedImageId(null);
    }
  };

  const handleAnalyze = async () => {
    if (!credentials) { setShowLogin(true); return; }
    if (!refFile) { alert("Vui lòng tải lên ảnh First Frame!"); return; }
    if (!prompt.trim()) { alert("Vui lòng nhập mô tả hành động!"); return; }

    setIsAnalyzing(true);
    setStatusMessage(`Đạo diễn đang tính toán diễn biến trong ${duration} giây...`);
    setShowScriptEditor(false);

    try {
        const refDataUrl = await fileToDataUrl(refFile);
        const structuredContext = await Promise.all(contextImages.map(async (img) => ({
            url: await fileToDataUrl(img.file),
            role: img.role
        })));

        const resultScript = await enhancePromptWithMotion(
            credentials, 
            prompt, 
            duration, 
            mode, 
            refDataUrl, 
            structuredContext
        );

        setOptimizedPrompt(resultScript);
        setShowScriptEditor(true); 
        setStatusMessage("Đã xong kịch bản Video. Vui lòng kiểm tra các lệnh Camera bên dưới.");
    } catch (error) {
        alert(`Lỗi phân tích: ${error instanceof Error ? error.message : "Unknown error"}`);
    } finally {
        setIsAnalyzing(false);
    }
  };

  const handleRenderDirector = async () => {
    if (!credentials || !refFile) return;

    // LOGIC FIX: If user skipped "Analyze", use the raw prompt.
    // If user Analyzed but cleared the text box, use raw prompt.
    const finalPromptToUse = optimizedPrompt.trim() ? optimizedPrompt : prompt;

    if (!finalPromptToUse.trim()) {
        alert("Vui lòng nhập ý tưởng hoặc tạo kịch bản trước khi Render.");
        return;
    }

    setIsRendering(true);
    setGeneratingCount(prev => prev + generationCount); 

    const contextMsg = contextImages.length > 0 
        ? `(Kèm ${contextImages.length} ảnh tham khảo)` 
        : '';
    setStatusMessage(`Đang Render ${generationCount} biến thể... ${contextMsg}`);

    try {
      const refDataUrl = await fileToDataUrl(refFile);
      const ctxDataUrls = await Promise.all(contextImages.map(img => fileToDataUrl(img.file)));

      const tasks = Array.from({ length: generationCount }).map(async (_, idx) => {
        try {
            const base64Image = await generateVideoFrame(
                credentials,
                finalPromptToUse, 
                aspectRatio, 
                resolution, 
                refDataUrl, 
                motionStrength,
                ctxDataUrls
            );

            const newImage: GeneratedImage = {
                id: Date.now().toString() + Math.random().toString().slice(2, 6),
                url: base64Image,
                timestamp: Date.now(),
                prompt: finalPromptToUse,
                ratio: aspectRatio
            };

            setResults(prev => [newImage, ...prev]);
        } catch (e) {
            console.error(`Task ${idx} failed`, e);
        } finally {
            setGeneratingCount(prev => Math.max(0, prev - 1));
        }
      });
      await Promise.all(tasks);
    } catch (error) {
      console.error(error);
      alert(`Lỗi Render: ${error instanceof Error ? error.message : "Error"}`);
      setGeneratingCount(0);
    } finally {
      setIsRendering(false);
      setStatusMessage('');
    }
  };

  // UI Helpers for Director Mode
  const isForward = mode === GenerationMode.FIRST_TO_LAST;

  const getRoleIcon = (role: ContextRole) => {
      switch(role) {
          case ContextRole.FACE: return <User size={12} />;
          case ContextRole.BACKGROUND: return <Mountain size={12} />;
          case ContextRole.STYLE: return <Palette size={12} />;
          case ContextRole.OUTFIT: return <Shirt size={12} />;
          case ContextRole.POSE: return <Move size={12} />;
          default: return <ImageIcon size={12} />;
      }
  };

  const getRoleLabel = (role: ContextRole) => {
      switch(role) {
          case ContextRole.FACE: return "Khuôn mặt";
          case ContextRole.BACKGROUND: return "Bối cảnh";
          case ContextRole.STYLE: return "Phong cách";
          case ContextRole.OUTFIT: return "Trang phục";
          case ContextRole.POSE: return "Tư thế/Dáng";
          default: return "Chung";
      }
  };

  // Nav
  const selectedImage = results.find(img => img.id === selectedImageId) || null;
  const selectedIndex = results.findIndex(img => img.id === selectedImageId);
  const handleNext = () => { if (selectedIndex < results.length - 1) setSelectedImageId(results[selectedIndex + 1].id); };
  const handlePrev = () => { if (selectedIndex > 0) setSelectedImageId(results[selectedIndex - 1].id); };

  return (
    <div className="min-h-screen bg-cinema-black text-zinc-100 font-sans selection:bg-cinema-accent selection:text-white pb-20">
      {showLogin && <ApiKeyModal onCredentialsSubmit={handleCredentials} />}

      {/* Header */}
      <header className="border-b border-zinc-800 bg-cinema-dark/50 backdrop-blur-md sticky top-0 z-40">
        <div className="container mx-auto px-6 py-4 flex items-center justify-between">
          <div className="flex items-center gap-3">
            {/* Logo Image */}
            <img 
              src="/YFilm%20Google.png" 
              alt="Logo" 
              className="w-10 h-10 rounded-lg shadow-lg shadow-rose-900/20 object-cover border border-zinc-700" 
            />
            <div>
              <h1 className="text-xl font-bold tracking-tight">Trợ Lý Đạo Diễn</h1>
              <p className="text-xs text-zinc-400">Chuyên Tạo Khung Hình (First/Last Frame) • Creative Studio</p>
            </div>
          </div>

          <div className="flex items-center gap-4">
             {generatingCount > 0 && (
                 <div className="flex items-center gap-2 px-3 py-1 bg-zinc-800 rounded-full text-xs text-yellow-500 animate-pulse border border-yellow-500/20">
                    <Loader2 size={12} className="animate-spin" />
                    <span>{generatingCount} ảnh đang chạy...</span>
                 </div>
             )}
             {credentials && (
                 <button 
                    onClick={() => setShowLogin(true)}
                    className="text-xs font-mono text-zinc-400 hover:text-white flex items-center gap-1 bg-zinc-900 border border-zinc-800 px-3 py-1.5 rounded-full transition-colors"
                 >
                    <Settings size={12} />
                    {credentials.baseUrl.replace(/(^\w+:|^)\/\//, '').split('/')[0]}...
                 </button>
             )}
          </div>
        </div>
      </header>

      <main className="container mx-auto px-6 py-8 grid grid-cols-1 lg:grid-cols-12 gap-8">

        {/* LEFT: Controls (Shared Area) */}
        <div className="lg:col-span-4 space-y-6">

          {/* TAB SWITCHER */}
          <div className="bg-zinc-900 p-1 rounded-xl flex font-medium border border-zinc-800">
            <button 
                onClick={() => setAppMode(AppMode.DIRECTOR)}
                className={`flex-1 py-2 rounded-lg flex items-center justify-center gap-2 text-sm transition-all ${appMode === AppMode.DIRECTOR ? 'bg-zinc-800 text-white shadow-sm ring-1 ring-zinc-700' : 'text-zinc-500 hover:text-white'}`}
            >
                <Clapperboard size={16} /> Đạo Diễn (Video)
            </button>
            <button 
                onClick={() => setAppMode(AppMode.CREATIVE)}
                className={`flex-1 py-2 rounded-lg flex items-center justify-center gap-2 text-sm transition-all ${appMode === AppMode.CREATIVE ? 'bg-zinc-800 text-white shadow-sm ring-1 ring-zinc-700' : 'text-zinc-500 hover:text-white'}`}
            >
                <Sparkles size={16} /> Sáng Tạo (Gen AI)
            </button>
          </div>

          {/* === MODE: DIRECTOR (Use CSS hidden to persist state) === */}
          <div className={appMode === AppMode.DIRECTOR ? 'space-y-6 animate-in fade-in' : 'hidden'}>
              {/* Director Direction Switch */}
              <div className="bg-cinema-gray p-1 rounded-lg flex text-sm font-medium border border-zinc-800">
                <button 
                  onClick={() => { setMode(GenerationMode.FIRST_TO_LAST); setPrompt(''); }}
                  className={`flex-1 py-2 rounded-md flex items-center justify-center gap-2 transition-all ${isForward ? 'bg-zinc-700 text-white shadow-sm' : 'text-zinc-400 hover:text-white'}`}
                >
                  <FastForward size={16} /> Start → End
                </button>
                <button 
                  onClick={() => { setMode(GenerationMode.LAST_TO_FIRST); setPrompt(''); }}
                  className={`flex-1 py-2 rounded-md flex items-center justify-center gap-2 transition-all ${!isForward ? 'bg-zinc-700 text-white shadow-sm' : 'text-zinc-400 hover:text-white'}`}
                >
                  <Rewind size={16} /> End → Start
                </button>
              </div>

              {/* Upload Section */}
              <div className="space-y-4">
                <div className="group relative">
                  <label className="block text-sm font-medium text-zinc-400 mb-2">
                    {isForward ? 'Ảnh Gốc (Start Frame)' : 'Ảnh Kết Thúc (End Frame)'} <span className="text-cinema-accent">*</span>
                  </label>
                  <div 
                    onClick={() => refInputRef.current?.click()}
                    className={`border-2 border-dashed border-zinc-700 rounded-xl h-48 flex flex-col items-center justify-center cursor-pointer transition-colors hover:border-cinema-accent hover:bg-zinc-800/50 relative overflow-hidden ${!refPreview ? 'bg-zinc-900' : ''}`}
                  >
                    {refPreview ? (
                      <img src={refPreview} alt="Ref" className="w-full h-full object-cover" />
                    ) : (
                      <>
                        <Upload className="w-8 h-8 text-zinc-500 mb-2 group-hover:text-cinema-accent transition-colors" />
                        <span className="text-xs text-zinc-500">
                            {isForward ? "Tải lên Start Frame" : "Tải lên End Frame"}
                        </span>
                      </>
                    )}
                    <input type="file" ref={refInputRef} onChange={handleRefUpload} className="hidden" accept="image/*" />
                  </div>
                </div>

                {/* Visual Context */}
                 <div className="group relative">
                  <label className="block text-sm font-medium text-zinc-400 mb-2 flex justify-between">
                    <span>Ngữ cảnh bổ sung (Visual Context)</span>
                  </label>

                  {contextImages.length > 0 && (
                      <div className="grid grid-cols-2 gap-3 mb-3">
                          {contextImages.map((img) => (
                              <div key={img.id} className="relative rounded-lg overflow-hidden border border-zinc-700 group/item bg-zinc-900 flex gap-2 p-1 items-center">
                                  <div className="w-16 h-16 shrink-0 relative rounded-md overflow-hidden">
                                      <img src={img.preview} alt="Ctx" className="w-full h-full object-cover" />
                                  </div>
                                  <div className="flex flex-col gap-1 w-full min-w-0 pr-1">
                                      <div className="flex items-center gap-1 text-[10px] text-zinc-400 uppercase font-bold">
                                          {getRoleIcon(img.role)} {getRoleLabel(img.role)}
                                      </div>
                                      <select 
                                        value={img.role} 
                                        onChange={(e) => updateContextRole(img.id, e.target.value as ContextRole)}
                                        className="w-full bg-zinc-800 text-[10px] border border-zinc-700 rounded p-1 text-white focus:outline-none focus:border-cinema-accent cursor-pointer"
                                      >
                                          <option value={ContextRole.GENERAL}>Chung (General)</option>
                                          <option value={ContextRole.FACE}>Khuôn mặt (Face)</option>
                                          <option value={ContextRole.BACKGROUND}>Bối cảnh (Bg)</option>
                                          <option value={ContextRole.OUTFIT}>Trang phục (Outfit)</option>
                                          <option value={ContextRole.STYLE}>Phong cách (Style)</option>
                                          <option value={ContextRole.POSE}>Tư thế (Pose)</option>
                                      </select>
                                  </div>
                                  <button onClick={() => removeContextImage(img.id)} className="absolute -top-1 -right-1 w-5 h-5 bg-red-900 text-white rounded-full flex items-center justify-center opacity-0 group-hover/item:opacity-100 transition-opacity z-10 hover:bg-red-600"><XCircle size={12} /></button>
                              </div>
                          ))}
                          <button onClick={() => ctxInputRef.current?.click()} className="h-16 rounded-lg border border-zinc-700 border-dashed flex items-center justify-center text-zinc-500 hover:text-white hover:border-zinc-500 transition-colors bg-zinc-900/50 w-full col-span-2"><Plus size={16} className="mr-2"/> Thêm ảnh tham khảo</button>
                      </div>
                  )}
                  {contextImages.length === 0 && (
                    <div onClick={() => ctxInputRef.current?.click()} className="border-2 border-dashed border-zinc-700 rounded-xl h-20 flex items-center justify-center cursor-pointer transition-colors hover:border-zinc-500 hover:bg-zinc-800/50 relative overflow-hidden bg-zinc-900">
                        <div className="flex items-center gap-2"><ImageIcon className="w-4 h-4 text-zinc-600" /><span className="text-xs text-zinc-500">Thêm ảnh tham khảo (Tùy chọn)</span></div>
                    </div>
                  )}
                  <input type="file" ref={ctxInputRef} onChange={handleCtxUpload} className="hidden" accept="image/*" multiple />
                </div>
              </div>

              {/* Prompt Section */}
              <div className="space-y-2">
                <label className="block text-sm font-medium text-zinc-400">Ý tưởng Video</label>
                <textarea
                  value={prompt}
                  onChange={(e) => setPrompt(e.target.value)}
                  placeholder="Mô tả hành động hoặc diễn biến tiếp theo (Ví dụ: Nhân vật quay đầu lại và cười...)"
                  className="w-full bg-zinc-900 border border-zinc-700 rounded-lg p-3 text-sm text-white placeholder-zinc-600 focus:outline-none focus:border-cinema-accent h-24 resize-none"
                />
              </div>

              {/* MOTION SETTINGS */}
              <div className="bg-zinc-900/50 p-4 rounded-xl border border-zinc-800 space-y-4">
                 <div>
                    <div className="flex justify-between items-center mb-2">
                         <label className="text-xs font-bold text-zinc-400 flex items-center gap-1"><Move size={12} /> BIÊN ĐỘ CHUYỂN ĐỘNG</label>
                         <span className="text-xs text-zinc-500">{motionStrength}</span>
                    </div>
                    <input 
                        type="range" min="1" max="3" step="1"
                        value={motionStrength === MotionStrength.LOW ? 1 : motionStrength === MotionStrength.MEDIUM ? 2 : 3}
                        onChange={(e) => {
                            const val = Number(e.target.value);
                            if(val === 1) setMotionStrength(MotionStrength.LOW);
                            if(val === 2) setMotionStrength(MotionStrength.MEDIUM);
                            if(val === 3) setMotionStrength(MotionStrength.HIGH);
                        }}
                        className="w-full h-2 bg-zinc-700 rounded-lg appearance-none cursor-pointer accent-cinema-accent"
                    />
                 </div>
                 <div className="grid grid-cols-2 gap-3 pt-2 border-t border-zinc-800">
                    <div>
                      <div className="flex justify-between items-end mb-1"><label className="block text-xs font-medium text-zinc-500">Thời lượng</label><span className="text-xs font-bold text-cinema-accent">{duration}s</span></div>
                      <input type="range" min="5" max="15" step="5" value={duration} onChange={(e) => setDuration(Number(e.target.value))} className="w-full h-2 bg-zinc-700 rounded-lg appearance-none cursor-pointer accent-cinema-accent" />
                    </div>
                    <div><label className="block text-xs font-medium text-zinc-500 mb-1">Số lượng</label><select value={generationCount} onChange={(e) => setGenerationCount(Number(e.target.value))} className="w-full bg-zinc-950 border border-zinc-700 rounded-md p-1.5 text-xs text-white"><option value={1}>1</option><option value={2}>2</option><option value={3}>3</option><option value={4}>4</option></select></div>
                    <div><label className="block text-xs font-medium text-zinc-500 mb-1">Tỉ lệ</label><select value={aspectRatio} onChange={(e) => setAspectRatio(e.target.value as AspectRatio)} className="w-full bg-zinc-950 border border-zinc-700 rounded-md p-1.5 text-xs">{ASPECT_RATIOS.map(r => <option key={r.value} value={r.value}>{r.label}</option>)}</select></div>
                    <div><label className="block text-xs font-medium text-zinc-500 mb-1">Chất lượng</label><select value={resolution} onChange={(e) => setResolution(e.target.value as Resolution)} className="w-full bg-zinc-950 border border-zinc-700 rounded-md p-1.5 text-xs">{RESOLUTIONS.map(r => <option key={r.value} value={r.value}>{r.label}</option>)}</select></div>
                 </div>
              </div>

              {/* ACTION BUTTONS (Director) */}
              {!showScriptEditor ? (
                  <button onClick={handleAnalyze} disabled={isAnalyzing} className={`w-full py-4 rounded-xl font-bold text-lg flex items-center justify-center gap-3 transition-all shadow-lg ${isAnalyzing ? 'bg-zinc-800 text-zinc-400 cursor-not-allowed' : 'bg-gradient-to-r from-blue-600 to-indigo-600 hover:from-blue-500 hover:to-indigo-500 text-white shadow-blue-900/30'}`}>
                    {isAnalyzing ? <Loader2 className="animate-spin" /> : <Clapperboard className="w-5 h-5" />}
                    {isAnalyzing ? 'Đạo Diễn Đang Suy Nghĩ...' : '1. Lên Kịch Bản'}
                  </button>
              ) : (
                <div className="bg-zinc-900 border border-indigo-500/50 rounded-xl p-4 animate-in fade-in slide-in-from-top-4 space-y-3 shadow-2xl shadow-indigo-900/20">
                    <div className="flex justify-between items-center">
                        <h3 className="text-sm font-bold text-indigo-400 flex items-center gap-2"><FileText size={16} /> Kịch Bản Đạo Diễn</h3>
                        <div className="flex gap-2">
                            <button onClick={copyScriptToClipboard} className="text-xs bg-zinc-800 hover:bg-zinc-700 text-zinc-300 px-2 py-1 rounded flex items-center gap-1 transition-colors"><Copy size={12} /> Copy</button>
                            <button onClick={handleAnalyze} className="text-xs text-zinc-500 hover:text-white flex items-center gap-1"><RefreshCw size={12} /> Làm lại</button>
                        </div>
                    </div>
                    <textarea value={optimizedPrompt} onChange={(e) => setOptimizedPrompt(e.target.value)} className="w-full h-40 bg-black/50 border border-zinc-700 rounded-lg p-3 text-xs font-mono text-zinc-300 focus:outline-none focus:border-indigo-500 resize-y" autoFocus />
                    <div className="flex gap-2 pt-2">
                         {isRendering ? (
                             <div className="flex gap-2 w-full">
                                <button disabled className="flex-1 py-3 bg-zinc-800 rounded-lg text-zinc-400 flex items-center justify-center gap-2 font-bold"><Loader2 className="animate-spin" size={18} /> Đang Render...</button>
                                 <button onClick={handleStopWaiting} className="px-4 bg-red-900/20 text-red-500 border border-red-900/50 rounded-lg hover:bg-red-900/40" title="Chạy ngầm (Mở khóa giao diện)"><Minimize2 size={20} /></button>
                             </div>
                         ) : (
                            <button onClick={handleRenderDirector} className="w-full py-3 rounded-lg font-bold text-base flex items-center justify-center gap-2 transition-all bg-gradient-to-r from-rose-600 to-red-600 hover:from-rose-500 hover:to-red-500 text-white shadow-lg shadow-rose-900/30"><Zap className="w-5 h-5 fill-white" /> 2. Render Ảnh</button>
                         )}
                    </div>
                </div>
              )}
              {statusMessage && <div className="text-xs text-center text-zinc-400 animate-pulse mt-2 px-4 border-l-2 border-cinema-accent bg-zinc-900/50 py-1">{statusMessage}</div>}
            </div>

          {/* === MODE: CREATIVE (Use CSS hidden to persist state) === */}
          <div className={appMode === AppMode.CREATIVE ? 'block' : 'hidden'}>
              <CreativeMode 
                credentials={credentials}
                onRequestLogin={() => setShowLogin(true)}
                onImageGenerated={(img) => setResults(prev => [img, ...prev])}
                setIsRendering={setIsRendering}
                setGeneratingCount={setGeneratingCount}
              />
          </div>

        </div>

        {/* RIGHT: Gallery (Shared for both modes) */}
        <div className="lg:col-span-8">
            <div className="flex items-center justify-between mb-6">
                <h2 className="text-xl font-bold flex items-center gap-2">
                    <PlaySquare className="text-zinc-500" />
                    Thư Viện Kết Quả
                </h2>
                <span className="text-sm text-zinc-500">{results.length} Frames</span>
            </div>

            {results.length === 0 ? (
                <div className="border border-zinc-800 border-dashed rounded-2xl h-[600px] flex flex-col items-center justify-center text-zinc-600 bg-zinc-900/30">
                    <Video className="w-16 h-16 mb-4 opacity-20" />
                    <p className="text-lg font-medium">Sẵn sàng tạo ảnh</p>
                    <p className="text-sm mt-2 opacity-60 max-w-md text-center">
                        {appMode === AppMode.DIRECTOR 
                            ? "Chế độ Đạo Diễn: Tạo Keyframe Start/End cho Video."
                            : "Chế độ Sáng Tạo: Tạo ảnh nghệ thuật từ văn bản và ảnh tham chiếu."}
                    </p>
                </div>
            ) : (
                <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
                    {results.map((img) => (
                        <div key={img.id} className="group relative bg-zinc-900 rounded-xl overflow-hidden border border-zinc-800 shadow-md hover:border-zinc-600 transition-all">
                            {/* Image Thumbnail */}
                            <div className="aspect-video w-full overflow-hidden bg-black relative cursor-zoom-in" onClick={() => setSelectedImageId(img.id)}>
                                <img src={img.url} alt="Result" className="w-full h-full object-contain" />
                                <div className="absolute top-2 left-2 bg-black/60 text-white px-2 py-0.5 rounded text-[10px] backdrop-blur-md">
                                    {img.ratio}
                                </div>
                            </div>

                            {/* Info */}
                            <div className="p-3">
                                <p className="text-xs text-zinc-500 line-clamp-2 mb-2 h-8" title={img.prompt}>
                                    {img.prompt}
                                </p>
                                <div className="flex justify-between items-center">
                                     <span className="text-[10px] text-zinc-600 font-mono">{new Date(img.timestamp).toLocaleTimeString()}</span>
                                     <div className="flex items-center gap-1">
                                        <button 
                                            onClick={(e) => { e.stopPropagation(); handleDeleteImage(img.id); }}
                                            className="text-zinc-500 hover:text-red-500 p-1.5 rounded-md hover:bg-zinc-800 transition-colors"
                                            title="Xóa ảnh"
                                        >
                                            <Trash2 size={16} />
                                        </button>
                                        <a href={img.url} download={`img_${img.id}.png`} className="text-zinc-400 hover:text-white p-1.5 rounded-md hover:bg-zinc-800 transition-colors" onClick={(e) => e.stopPropagation()}>
                                            <Download size={16} />
                                        </a>
                                     </div>
                                </div>
                            </div>
                        </div>
                    ))}
                </div>
            )}
        </div>

      </main>

      {selectedImage && (
        <ImageViewer 
            image={selectedImage} 
            onClose={() => setSelectedImageId(null)}
            onNext={handleNext}
            onPrev={handlePrev}
            hasNext={selectedIndex < results.length - 1}
            hasPrev={selectedIndex > 0}
        />
      )}
    </div>
  );
}

import React, { useEffect, useState } from 'react';
import { ApiCredentials } from '../types';
import { Key, Server, LogIn, AlertTriangle, Globe, ShieldAlert, Wifi, Cloud } from 'lucide-react';

interface ApiKeyModalProps {
  onCredentialsSubmit: (creds: ApiCredentials) => void;
}

// Các URL gợi ý dựa trên yêu cầu của bạn
const SUGGESTED_URLS = [
  { label: "Localhost (Máy cá nhân)", url: "http://127.0.0.1:8045/v1", icon: <Server size={12} /> },
  { label: "Mạng LAN (IP Tĩnh)", url: "http://192.168.1.22:8045/v1", icon: <Wifi size={12} /> },
  { label: "Public Tunnel (Cloudflare)", url: "https://improved-communication-transmit-retain.trycloudflare.com/v1", icon: <Cloud size={12} /> }
];

const ApiKeyModal: React.FC<ApiKeyModalProps> = ({ onCredentialsSubmit }) => {
  const [isOpen, setIsOpen] = useState(true);
  const [baseUrl, setBaseUrl] = useState('http://127.0.0.1:8045/v1');
  const [apiKey, setApiKey] = useState('sk-715c78c494c34e7493ff66af32cc7200');

  // Detection states
  const [isHttps, setIsHttps] = useState(false);
  const [isLocalhost, setIsLocalhost] = useState(false);

  useEffect(() => {
    setIsHttps(window.location.protocol === 'https:');

    const storedBaseUrl = localStorage.getItem('app_base_url');
    const storedApiKey = localStorage.getItem('app_api_key');

    if (storedBaseUrl) {
        setBaseUrl(storedBaseUrl);
        checkLocalhost(storedBaseUrl);
    }
    if (storedApiKey) setApiKey(storedApiKey);
    else checkLocalhost('http://127.0.0.1:8045/v1'); 
  }, []);

  const checkLocalhost = (url: string) => {
      const isLocal = url.includes('127.0.0.1') || url.includes('localhost') || url.startsWith('http://0.0.0.0') || url.startsWith('http://192.168.');
      setIsLocalhost(isLocal);
  };

  const handleBaseUrlChange = (e: React.ChangeEvent<HTMLInputElement>) => {
      const val = e.target.value;
      setBaseUrl(val);
      checkLocalhost(val);
  };

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (!baseUrl || !apiKey) {
        alert("Vui lòng nhập đầy đủ thông tin");
        return;
    }

    let formattedUrl = baseUrl;
    if (formattedUrl.endsWith('/')) {
        formattedUrl = formattedUrl.slice(0, -1);
    }

    localStorage.setItem('app_base_url', formattedUrl);
    localStorage.setItem('app_api_key', apiKey);

    onCredentialsSubmit({ baseUrl: formattedUrl, apiKey });
    setIsOpen(false);
  };

  if (!isOpen) return null;

  return (
    <div className="fixed inset-0 z-50 flex items-center justify-center bg-black/95 backdrop-blur-md px-4">
      <div className="bg-cinema-gray border border-zinc-700 p-8 rounded-xl max-w-lg w-full shadow-2xl relative overflow-hidden">

        <div className="text-center mb-6 relative z-10 flex flex-col items-center">
            {/* Logo Image */}
            <img src="/YFilm%20Google.png" alt="Logo" className="w-16 h-16 rounded-xl shadow-2xl mb-4 border border-zinc-700 object-cover" />
            <h2 className="text-2xl font-bold text-white">Kết Nối Đạo Diễn AI</h2>
            <p className="text-zinc-400 text-sm mt-2">Dùng API OpenAI (Google Banana Pro)</p>
        </div>

        <form onSubmit={handleSubmit} className="space-y-5 relative z-10">
            <div>
                <label className="block text-xs font-medium text-zinc-500 mb-2 flex items-center gap-2">
                    <Server size={14} /> Base URL (API Endpoint)
                </label>

                {/* Suggestions Chips */}
                <div className="flex flex-wrap gap-2 mb-3">
                    {SUGGESTED_URLS.map((opt) => (
                        <button
                            key={opt.url}
                            type="button"
                            onClick={() => { setBaseUrl(opt.url); checkLocalhost(opt.url); }}
                            className={`text-[10px] flex items-center gap-1.5 px-2 py-1.5 rounded border transition-colors ${baseUrl === opt.url ? 'bg-cinema-accent border-cinema-accent text-white' : 'bg-zinc-900 border-zinc-700 text-zinc-400 hover:border-zinc-500'}`}
                        >
                            {opt.icon} {opt.label}
                        </button>
                    ))}
                </div>

                <div className="relative">
                    <input 
                        type="text" 
                        value={baseUrl}
                        onChange={handleBaseUrlChange}
                        placeholder="Nhập Base URL..."
                        className={`w-full bg-zinc-900 border rounded-lg p-3 pl-10 text-sm text-white focus:outline-none transition-colors ${
                            isHttps && isLocalhost ? 'border-yellow-600 focus:border-yellow-500' : 'border-zinc-700 focus:border-cinema-accent'
                        }`}
                    />
                    <div className="absolute left-3 top-3 text-zinc-500">
                        {isLocalhost ? <ShieldAlert size={16} className={isHttps ? "text-yellow-500" : ""} /> : <Globe size={16} />}
                    </div>
                </div>
            </div>

            {/* Smart Warning for Mixed Content */}
            {isHttps && isLocalhost && (
                <div className="bg-yellow-900/20 border border-yellow-700/50 rounded-lg p-3 flex gap-3 items-start">
                    <AlertTriangle className="text-yellow-500 shrink-0 mt-0.5" size={18} />
                    <div className="text-xs text-zinc-300">
                        <strong className="text-yellow-500 block mb-1">Cảnh báo Mixed Content:</strong>
                        App đang chạy trên <strong>HTTPS</strong> nhưng API là <strong>HTTP</strong> (Localhost/LAN).
                        <ul className="list-disc list-inside mt-2 text-zinc-400 space-y-1">
                            <li>Khuyên dùng: Sử dụng <strong>Cloudflare Tunnel</strong> (https) để kết nối ổn định.</li>
                            <li>Hoặc: Chạy App này ở Localhost (http).</li>
                        </ul>
                    </div>
                </div>
            )}

            <div>
                <label className="block text-xs font-medium text-zinc-500 mb-1 flex items-center gap-2">
                    <Key size={14} /> API Key
                </label>
                <input 
                    type="password" 
                    value={apiKey}
                    onChange={(e) => setApiKey(e.target.value)}
                    placeholder="sk-..."
                    className="w-full bg-zinc-900 border border-zinc-700 rounded-lg p-3 text-sm text-white focus:border-cinema-accent focus:outline-none"
                />
            </div>

            <button
                type="submit"
                className="w-full bg-cinema-accent hover:bg-rose-700 text-white font-bold py-3 px-6 rounded-lg transition-all flex items-center justify-center gap-2 mt-4"
            >
                <LogIn size={18} />
                Kết nối Server
            </button>
        </form>

        <div className="mt-6 text-[10px] text-zinc-600 border-t border-zinc-800 pt-4 flex justify-between gap-4">
             <span>Gemini 3 Flash (Scripting/Reasoning)</span>
             <span>Gemini 3 Pro Image (Generation)</span>
        </div>
      </div>
    </div>
  );
};

export default ApiKeyModal;

import React, { useState, useRef } from 'react';
import { AspectRatio, Resolution, GenerationMode, GeneratedImage, ApiCredentials, MotionStrength, ContextImage, ContextRole, AppMode } from './types';
import { ASPECT_RATIOS, RESOLUTIONS } from './constants';
import { fileToDataUrl, enhancePromptWithMotion, generateVideoFrame } from './services/geminiService';
import { Upload, Wand2, Image as ImageIcon, Loader2, PlaySquare, Rewind, FastForward, Download, Settings, Trash2, Plus, XCircle, Minimize2, Move, Video, Zap, FileText, RefreshCw, Copy, Clapperboard, User, Mountain, Palette, Shirt, Sparkles } from 'lucide-react';
import ApiKeyModal from './components/ApiKeyModal';
import ImageViewer from './components/ImageViewer';
import CreativeMode from './components/CreativeMode';

export default function App() {
  const [credentials, setCredentials] = useState<ApiCredentials | null>(null);

  // App Mode State
  const [appMode, setAppMode] = useState<AppMode>(AppMode.DIRECTOR);

  // --- DIRECTOR MODE STATE ---
  const [prompt, setPrompt] = useState('');
  const [duration, setDuration] = useState(5);
  const [aspectRatio, setAspectRatio] = useState<AspectRatio>(AspectRatio.R_16_9);
  const [resolution, setResolution] = useState<Resolution>(Resolution.RES_1K);
  const [generationCount, setGenerationCount] = useState(1);
  const [mode, setMode] = useState<GenerationMode>(GenerationMode.FIRST_TO_LAST);
  const [motionStrength, setMotionStrength] = useState<MotionStrength>(MotionStrength.MEDIUM);

  const [refFile, setRefFile] = useState<File | null>(null);
  const [refPreview, setRefPreview] = useState<string | null>(null);
  const [contextImages, setContextImages] = useState<ContextImage[]>([]);

  const [optimizedPrompt, setOptimizedPrompt] = useState<string>('');
  const [isAnalyzing, setIsAnalyzing] = useState(false);
  const [showScriptEditor, setShowScriptEditor] = useState(false);
  // ---------------------------

  // Shared Output State
  const [isRendering, setIsRendering] = useState(false);
  const [generatingCount, setGeneratingCount] = useState(0); 
  const [statusMessage, setStatusMessage] = useState('');
  const [results, setResults] = useState<GeneratedImage[]>([]);
  const [selectedImageId, setSelectedImageId] = useState<string | null>(null);
  const [showLogin, setShowLogin] = useState(true);

  // Logo Error State
  const [logoError, setLogoError] = useState(false);

  const refInputRef = useRef<HTMLInputElement>(null);
  const ctxInputRef = useRef<HTMLInputElement>(null);

  const handleCredentials = (creds: ApiCredentials) => {
    setCredentials(creds);
    setShowLogin(false);
  };

  // --- DIRECTOR HANDLERS ---
  const handleRefUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
    if (e.target.files && e.target.files[0]) {
      const file = e.target.files[0];
      setRefFile(file);
      setRefPreview(URL.createObjectURL(file as Blob));
      setOptimizedPrompt('');
      setShowScriptEditor(false);
    }
  };

  const handleCtxUpload = async (e: React.ChangeEvent<HTMLInputElement>) => {
    if (e.target.files && e.target.files.length > 0) {
      const newFiles: File[] = Array.from(e.target.files);
      const newImages: ContextImage[] = newFiles.map(file => ({
        id: Math.random().toString(36).substring(7),
        file,
        preview: URL.createObjectURL(file),
        role: ContextRole.GENERAL 
      }));
      setContextImages(prev => [...prev, ...newImages]);
    }
    if (ctxInputRef.current) ctxInputRef.current.value = '';
  };

  const updateContextRole = (id: string, newRole: ContextRole) => {
    setContextImages(prev => prev.map(img => 
        img.id === id ? { ...img, role: newRole } : img
    ));
  };

  const removeContextImage = (id: string) => {
    setContextImages(prev => prev.filter(img => img.id !== id));
  };

  const handleStopWaiting = () => {
    setIsRendering(false);
    setStatusMessage("Đã ẩn trạng thái chờ. Các ảnh đang tạo sẽ tự động hiện khi hoàn tất (Chạy ngầm).");
  };

  const copyScriptToClipboard = () => {
    navigator.clipboard.writeText(optimizedPrompt);
    setStatusMessage("Đã copy kịch bản vào bộ nhớ đệm!");
    setTimeout(() => setStatusMessage(''), 2000);
  };

  const handleDeleteImage = (id: string) => {
    if (window.confirm("Bạn có chắc chắn muốn xóa ảnh này không?")) {
      setResults(prev => prev.filter(img => img.id !== id));
      if (selectedImageId === id) setSelectedImageId(null);
    }
  };

  const handleAnalyze = async () => {
    if (!credentials) { setShowLogin(true); return; }
    if (!refFile) { alert("Vui lòng tải lên ảnh First Frame!"); return; }
    if (!prompt.trim()) { alert("Vui lòng nhập mô tả hành động!"); return; }

    setIsAnalyzing(true);
    setStatusMessage(`Đạo diễn đang tính toán diễn biến trong ${duration} giây...`);
    setShowScriptEditor(false);

    try {
        const refDataUrl = await fileToDataUrl(refFile);
        const structuredContext = await Promise.all(contextImages.map(async (img) => ({
            url: await fileToDataUrl(img.file),
            role: img.role
        })));

        const resultScript = await enhancePromptWithMotion(
            credentials, 
            prompt, 
            duration, 
            mode, 
            refDataUrl, 
            structuredContext
        );

        setOptimizedPrompt(resultScript);
        setShowScriptEditor(true); 
        setStatusMessage("Đã xong kịch bản Video. Vui lòng kiểm tra các lệnh Camera bên dưới.");
    } catch (error) {
        alert(`Lỗi phân tích: ${error instanceof Error ? error.message : "Unknown error"}`);
    } finally {
        setIsAnalyzing(false);
    }
  };

  const handleRenderDirector = async () => {
    if (!credentials || !refFile) return;

    // LOGIC FIX: If user skipped "Analyze", use the raw prompt.
    // If user Analyzed but cleared the text box, use raw prompt.
    const finalPromptToUse = optimizedPrompt.trim() ? optimizedPrompt : prompt;

    if (!finalPromptToUse.trim()) {
        alert("Vui lòng nhập ý tưởng hoặc tạo kịch bản trước khi Render.");
        return;
    }

    setIsRendering(true);
    setGeneratingCount(prev => prev + generationCount); 

    const contextMsg = contextImages.length > 0 
        ? `(Kèm ${contextImages.length} ảnh tham khảo)` 
        : '';
    setStatusMessage(`Đang Render ${generationCount} biến thể... ${contextMsg}`);

    try {
      const refDataUrl = await fileToDataUrl(refFile);
      const ctxDataUrls = await Promise.all(contextImages.map(img => fileToDataUrl(img.file)));

      const tasks = Array.from({ length: generationCount }).map(async (_, idx) => {
        try {
            const base64Image = await generateVideoFrame(
                credentials,
                finalPromptToUse, 
                aspectRatio, 
                resolution, 
                refDataUrl, 
                motionStrength,
                ctxDataUrls
            );

            const newImage: GeneratedImage = {
                id: Date.now().toString() + Math.random().toString().slice(2, 6),
                url: base64Image,
                timestamp: Date.now(),
                prompt: finalPromptToUse,
                ratio: aspectRatio
            };

            setResults(prev => [newImage, ...prev]);
        } catch (e) {
            console.error(`Task ${idx} failed`, e);
        } finally {
            setGeneratingCount(prev => Math.max(0, prev - 1));
        }
      });
      await Promise.all(tasks);
    } catch (error) {
      console.error(error);
      alert(`Lỗi Render: ${error instanceof Error ? error.message : "Error"}`);
      setGeneratingCount(0);
    } finally {
      setIsRendering(false);
      setStatusMessage('');
    }
  };

  // UI Helpers for Director Mode
  const isForward = mode === GenerationMode.FIRST_TO_LAST;

  const getRoleIcon = (role: ContextRole) => {
      switch(role) {
          case ContextRole.FACE: return <User size={12} />;
          case ContextRole.BACKGROUND: return <Mountain size={12} />;
          case ContextRole.STYLE: return <Palette size={12} />;
          case ContextRole.OUTFIT: return <Shirt size={12} />;
          case ContextRole.POSE: return <Move size={12} />;
          default: return <ImageIcon size={12} />;
      }
  };

  const getRoleLabel = (role: ContextRole) => {
      switch(role) {
          case ContextRole.FACE: return "Khuôn mặt";
          case ContextRole.BACKGROUND: return "Bối cảnh";
          case ContextRole.STYLE: return "Phong cách";
          case ContextRole.OUTFIT: return "Trang phục";
          case ContextRole.POSE: return "Tư thế/Dáng";
          default: return "Chung";
      }
  };

  // Nav
  const selectedImage = results.find(img => img.id === selectedImageId) || null;
  const selectedIndex = results.findIndex(img => img.id === selectedImageId);
  const handleNext = () => { if (selectedIndex < results.length - 1) setSelectedImageId(results[selectedIndex + 1].id); };
  const handlePrev = () => { if (selectedIndex > 0) setSelectedImageId(results[selectedIndex - 1].id); };

  return (
    <div className="min-h-screen bg-cinema-black text-zinc-100 font-sans selection:bg-cinema-accent selection:text-white pb-20">
      {showLogin && <ApiKeyModal onCredentialsSubmit={handleCredentials} />}

      {/* Header */}
      <header className="border-b border-zinc-800 bg-cinema-dark/50 backdrop-blur-md sticky top-0 z-40">
        <div className="container mx-auto px-6 py-4 flex items-center justify-between">
          <div className="flex items-center gap-3">
            {/* Logo Image with Error Fallback */}
            {logoError ? (
                <div className="w-10 h-10 rounded-lg bg-rose-600 flex items-center justify-center shadow-lg shadow-rose-900/20">
                    <Video className="text-white" size={20} />
                </div>
            ) : (
                <img 
                  src="YFilm%20Google.png" 
                  alt="Logo" 
                  className="w-10 h-10 rounded-lg shadow-lg shadow-rose-900/20 object-cover border border-zinc-700"
                  onError={() => setLogoError(true)}
                />
            )}
            <div>
              <h1 className="text-xl font-bold tracking-tight">Trợ Lý Đạo Diễn</h1>
              <p className="text-xs text-zinc-400">Chuyên Tạo Khung Hình (First/Last Frame) • Creative Studio</p>
            </div>
          </div>

          <div className="flex items-center gap-4">
             {generatingCount > 0 && (
                 <div className="flex items-center gap-2 px-3 py-1 bg-zinc-800 rounded-full text-xs text-yellow-500 animate-pulse border border-yellow-500/20">
                    <Loader2 size={12} className="animate-spin" />
                    <span>{generatingCount} ảnh đang chạy...</span>
                 </div>
             )}
             {credentials && (
                 <button 
                    onClick={() => setShowLogin(true)}
                    className="text-xs font-mono text-zinc-400 hover:text-white flex items-center gap-1 bg-zinc-900 border border-zinc-800 px-3 py-1.5 rounded-full transition-colors"
                 >
                    <Settings size={12} />
                    {credentials.baseUrl.replace(/(^\w+:|^)\/\//, '').split('/')[0]}...
                 </button>
             )}
          </div>
        </div>
      </header>

      <main className="container mx-auto px-6 py-8 grid grid-cols-1 lg:grid-cols-12 gap-8">

        {/* LEFT: Controls (Shared Area) */}
        <div className="lg:col-span-4 space-y-6">

          {/* TAB SWITCHER */}
          <div className="bg-zinc-900 p-1 rounded-xl flex font-medium border border-zinc-800">
            <button 
                onClick={() => setAppMode(AppMode.DIRECTOR)}
                className={`flex-1 py-2 rounded-lg flex items-center justify-center gap-2 text-sm transition-all ${appMode === AppMode.DIRECTOR ? 'bg-zinc-800 text-white shadow-sm ring-1 ring-zinc-700' : 'text-zinc-500 hover:text-white'}`}
            >
                <Clapperboard size={16} /> Đạo Diễn (Video)
            </button>
            <button 
                onClick={() => setAppMode(AppMode.CREATIVE)}
                className={`flex-1 py-2 rounded-lg flex items-center justify-center gap-2 text-sm transition-all ${appMode === AppMode.CREATIVE ? 'bg-zinc-800 text-white shadow-sm ring-1 ring-zinc-700' : 'text-zinc-500 hover:text-white'}`}
            >
                <Sparkles size={16} /> Sáng Tạo (Gen AI)
            </button>
          </div>

          {/* === MODE: DIRECTOR (Use CSS hidden to persist state) === */}
          <div className={appMode === AppMode.DIRECTOR ? 'space-y-6 animate-in fade-in' : 'hidden'}>
              {/* Director Direction Switch */}
              <div className="bg-cinema-gray p-1 rounded-lg flex text-sm font-medium border border-zinc-800">
                <button 
                  onClick={() => { setMode(GenerationMode.FIRST_TO_LAST); setPrompt(''); }}
                  className={`flex-1 py-2 rounded-md flex items-center justify-center gap-2 transition-all ${isForward ? 'bg-zinc-700 text-white shadow-sm' : 'text-zinc-400 hover:text-white'}`}
                >
                  <FastForward size={16} /> Start → End
                </button>
                <button 
                  onClick={() => { setMode(GenerationMode.LAST_TO_FIRST); setPrompt(''); }}
                  className={`flex-1 py-2 rounded-md flex items-center justify-center gap-2 transition-all ${!isForward ? 'bg-zinc-700 text-white shadow-sm' : 'text-zinc-400 hover:text-white'}`}
                >
                  <Rewind size={16} /> End → Start
                </button>
              </div>

              {/* Upload Section */}
              <div className="space-y-4">
                <div className="group relative">
                  <label className="block text-sm font-medium text-zinc-400 mb-2">
                    {isForward ? 'Ảnh Gốc (Start Frame)' : 'Ảnh Kết Thúc (End Frame)'} <span className="text-cinema-accent">*</span>
                  </label>
                  <div 
                    onClick={() => refInputRef.current?.click()}
                    className={`border-2 border-dashed border-zinc-700 rounded-xl h-48 flex flex-col items-center justify-center cursor-pointer transition-colors hover:border-cinema-accent hover:bg-zinc-800/50 relative overflow-hidden ${!refPreview ? 'bg-zinc-900' : ''}`}
                  >
                    {refPreview ? (
                      <img src={refPreview} alt="Ref" className="w-full h-full object-cover" />
                    ) : (
                      <>
                        <Upload className="w-8 h-8 text-zinc-500 mb-2 group-hover:text-cinema-accent transition-colors" />
                        <span className="text-xs text-zinc-500">
                            {isForward ? "Tải lên Start Frame" : "Tải lên End Frame"}
                        </span>
                      </>
                    )}
                    <input type="file" ref={refInputRef} onChange={handleRefUpload} className="hidden" accept="image/*" />
                  </div>
                </div>

                {/* Visual Context */}
                 <div className="group relative">
                  <label className="block text-sm font-medium text-zinc-400 mb-2 flex justify-between">
                    <span>Ngữ cảnh bổ sung (Visual Context)</span>
                  </label>

                  {contextImages.length > 0 && (
                      <div className="grid grid-cols-2 gap-3 mb-3">
                          {contextImages.map((img) => (
                              <div key={img.id} className="relative rounded-lg overflow-hidden border border-zinc-700 group/item bg-zinc-900 flex gap-2 p-1 items-center">
                                  <div className="w-16 h-16 shrink-0 relative rounded-md overflow-hidden">
                                      <img src={img.preview} alt="Ctx" className="w-full h-full object-cover" />
                                  </div>
                                  <div className="flex flex-col gap-1 w-full min-w-0 pr-1">
                                      <div className="flex items-center gap-1 text-[10px] text-zinc-400 uppercase font-bold">
                                          {getRoleIcon(img.role)} {getRoleLabel(img.role)}
                                      </div>
                                      <select 
                                        value={img.role} 
                                        onChange={(e) => updateContextRole(img.id, e.target.value as ContextRole)}
                                        className="w-full bg-zinc-800 text-[10px] border border-zinc-700 rounded p-1 text-white focus:outline-none focus:border-cinema-accent cursor-pointer"
                                      >
                                          <option value={ContextRole.GENERAL}>Chung (General)</option>
                                          <option value={ContextRole.FACE}>Khuôn mặt (Face)</option>
                                          <option value={ContextRole.BACKGROUND}>Bối cảnh (Bg)</option>
                                          <option value={ContextRole.OUTFIT}>Trang phục (Outfit)</option>
                                          <option value={ContextRole.STYLE}>Phong cách (Style)</option>
                                          <option value={ContextRole.POSE}>Tư thế (Pose)</option>
                                      </select>
                                  </div>
                                  <button onClick={() => removeContextImage(img.id)} className="absolute -top-1 -right-1 w-5 h-5 bg-red-900 text-white rounded-full flex items-center justify-center opacity-0 group-hover/item:opacity-100 transition-opacity z-10 hover:bg-red-600"><XCircle size={12} /></button>
                              </div>
                          ))}
                          <button onClick={() => ctxInputRef.current?.click()} className="h-16 rounded-lg border border-zinc-700 border-dashed flex items-center justify-center text-zinc-500 hover:text-white hover:border-zinc-500 transition-colors bg-zinc-900/50 w-full col-span-2"><Plus size={16} className="mr-2"/> Thêm ảnh tham khảo</button>
                      </div>
                  )}
                  {contextImages.length === 0 && (
                    <div onClick={() => ctxInputRef.current?.click()} className="border-2 border-dashed border-zinc-700 rounded-xl h-20 flex items-center justify-center cursor-pointer transition-colors hover:border-zinc-500 hover:bg-zinc-800/50 relative overflow-hidden bg-zinc-900">
                        <div className="flex items-center gap-2"><ImageIcon className="w-4 h-4 text-zinc-600" /><span className="text-xs text-zinc-500">Thêm ảnh tham khảo (Tùy chọn)</span></div>
                    </div>
                  )}
                  <input type="file" ref={ctxInputRef} onChange={handleCtxUpload} className="hidden" accept="image/*" multiple />
                </div>
              </div>

              {/* Prompt Section */}
              <div className="space-y-2">
                <label className="block text-sm font-medium text-zinc-400">Ý tưởng Video</label>
                <textarea
                  value={prompt}
                  onChange={(e) => setPrompt(e.target.value)}
                  placeholder="Mô tả hành động hoặc diễn biến tiếp theo (Ví dụ: Nhân vật quay đầu lại và cười...)"
                  className="w-full bg-zinc-900 border border-zinc-700 rounded-lg p-3 text-sm text-white placeholder-zinc-600 focus:outline-none focus:border-cinema-accent h-24 resize-none"
                />
              </div>

              {/* MOTION SETTINGS */}
              <div className="bg-zinc-900/50 p-4 rounded-xl border border-zinc-800 space-y-4">
                 <div>
                    <div className="flex justify-between items-center mb-2">
                         <label className="text-xs font-bold text-zinc-400 flex items-center gap-1"><Move size={12} /> BIÊN ĐỘ CHUYỂN ĐỘNG</label>
                         <span className="text-xs text-zinc-500">{motionStrength}</span>
                    </div>
                    <input 
                        type="range" min="1" max="3" step="1"
                        value={motionStrength === MotionStrength.LOW ? 1 : motionStrength === MotionStrength.MEDIUM ? 2 : 3}
                        onChange={(e) => {
                            const val = Number(e.target.value);
                            if(val === 1) setMotionStrength(MotionStrength.LOW);
                            if(val === 2) setMotionStrength(MotionStrength.MEDIUM);
                            if(val === 3) setMotionStrength(MotionStrength.HIGH);
                        }}
                        className="w-full h-2 bg-zinc-700 rounded-lg appearance-none cursor-pointer accent-cinema-accent"
                    />
                 </div>
                 <div className="grid grid-cols-2 gap-3 pt-2 border-t border-zinc-800">
                    <div>
                      <div className="flex justify-between items-end mb-1"><label className="block text-xs font-medium text-zinc-500">Thời lượng</label><span className="text-xs font-bold text-cinema-accent">{duration}s</span></div>
                      <input type="range" min="5" max="15" step="5" value={duration} onChange={(e) => setDuration(Number(e.target.value))} className="w-full h-2 bg-zinc-700 rounded-lg appearance-none cursor-pointer accent-cinema-accent" />
                    </div>
                    <div><label className="block text-xs font-medium text-zinc-500 mb-1">Số lượng</label><select value={generationCount} onChange={(e) => setGenerationCount(Number(e.target.value))} className="w-full bg-zinc-950 border border-zinc-700 rounded-md p-1.5 text-xs text-white"><option value={1}>1</option><option value={2}>2</option><option value={3}>3</option><option value={4}>4</option></select></div>
                    <div><label className="block text-xs font-medium text-zinc-500 mb-1">Tỉ lệ</label><select value={aspectRatio} onChange={(e) => setAspectRatio(e.target.value as AspectRatio)} className="w-full bg-zinc-950 border border-zinc-700 rounded-md p-1.5 text-xs">{ASPECT_RATIOS.map(r => <option key={r.value} value={r.value}>{r.label}</option>)}</select></div>
                    <div><label className="block text-xs font-medium text-zinc-500 mb-1">Chất lượng</label><select value={resolution} onChange={(e) => setResolution(e.target.value as Resolution)} className="w-full bg-zinc-950 border border-zinc-700 rounded-md p-1.5 text-xs">{RESOLUTIONS.map(r => <option key={r.value} value={r.value}>{r.label}</option>)}</select></div>
                 </div>
              </div>

              {/* ACTION BUTTONS (Director) */}
              {!showScriptEditor ? (
                  <button onClick={handleAnalyze} disabled={isAnalyzing} className={`w-full py-4 rounded-xl font-bold text-lg flex items-center justify-center gap-3 transition-all shadow-lg ${isAnalyzing ? 'bg-zinc-800 text-zinc-400 cursor-not-allowed' : 'bg-gradient-to-r from-blue-600 to-indigo-600 hover:from-blue-500 hover:to-indigo-500 text-white shadow-blue-900/30'}`}>
                    {isAnalyzing ? <Loader2 className="animate-spin" /> : <Clapperboard className="w-5 h-5" />}
                    {isAnalyzing ? 'Đạo Diễn Đang Suy Nghĩ...' : '1. Lên Kịch Bản'}
                  </button>
              ) : (
                <div className="bg-zinc-900 border border-indigo-500/50 rounded-xl p-4 animate-in fade-in slide-in-from-top-4 space-y-3 shadow-2xl shadow-indigo-900/20">
                    <div className="flex justify-between items-center">
                        <h3 className="text-sm font-bold text-indigo-400 flex items-center gap-2"><FileText size={16} /> Kịch Bản Đạo Diễn</h3>
                        <div className="flex gap-2">
                            <button onClick={copyScriptToClipboard} className="text-xs bg-zinc-800 hover:bg-zinc-700 text-zinc-300 px-2 py-1 rounded flex items-center gap-1 transition-colors"><Copy size={12} /> Copy</button>
                            <button onClick={handleAnalyze} className="text-xs text-zinc-500 hover:text-white flex items-center gap-1"><RefreshCw size={12} /> Làm lại</button>
                        </div>
                    </div>
                    <textarea value={optimizedPrompt} onChange={(e) => setOptimizedPrompt(e.target.value)} className="w-full h-40 bg-black/50 border border-zinc-700 rounded-lg p-3 text-xs font-mono text-zinc-300 focus:outline-none focus:border-indigo-500 resize-y" autoFocus />
                    <div className="flex gap-2 pt-2">
                         {isRendering ? (
                             <div className="flex gap-2 w-full">
                                <button disabled className="flex-1 py-3 bg-zinc-800 rounded-lg text-zinc-400 flex items-center justify-center gap-2 font-bold"><Loader2 className="animate-spin" size={18} /> Đang Render...</button>
                                 <button onClick={handleStopWaiting} className="px-4 bg-red-900/20 text-red-500 border border-red-900/50 rounded-lg hover:bg-red-900/40" title="Chạy ngầm (Mở khóa giao diện)"><Minimize2 size={20} /></button>
                             </div>
                         ) : (
                            <button onClick={handleRenderDirector} className="w-full py-3 rounded-lg font-bold text-base flex items-center justify-center gap-2 transition-all bg-gradient-to-r from-rose-600 to-red-600 hover:from-rose-500 hover:to-red-500 text-white shadow-lg shadow-rose-900/30"><Zap className="w-5 h-5 fill-white" /> 2. Render Ảnh</button>
                         )}
                    </div>
                </div>
              )}
              {statusMessage && <div className="text-xs text-center text-zinc-400 animate-pulse mt-2 px-4 border-l-2 border-cinema-accent bg-zinc-900/50 py-1">{statusMessage}</div>}
            </div>

          {/* === MODE: CREATIVE (Use CSS hidden to persist state) === */}
          <div className={appMode === AppMode.CREATIVE ? 'block' : 'hidden'}>
              <CreativeMode 
                credentials={credentials}
                onRequestLogin={() => setShowLogin(true)}
                onImageGenerated={(img) => setResults(prev => [img, ...prev])}
                setIsRendering={setIsRendering}
                setGeneratingCount={setGeneratingCount}
              />
          </div>

        </div>

        {/* RIGHT: Gallery (Shared for both modes) */}
        <div className="lg:col-span-8">
            <div className="flex items-center justify-between mb-6">
                <h2 className="text-xl font-bold flex items-center gap-2">
                    <PlaySquare className="text-zinc-500" />
                    Thư Viện Kết Quả
                </h2>
                <span className="text-sm text-zinc-500">{results.length} Frames</span>
            </div>

            {results.length === 0 ? (
                <div className="border border-zinc-800 border-dashed rounded-2xl h-[600px] flex flex-col items-center justify-center text-zinc-600 bg-zinc-900/30">
                    <Video className="w-16 h-16 mb-4 opacity-20" />
                    <p className="text-lg font-medium">Sẵn sàng tạo ảnh</p>
                    <p className="text-sm mt-2 opacity-60 max-w-md text-center">
                        {appMode === AppMode.DIRECTOR 
                            ? "Chế độ Đạo Diễn: Tạo Keyframe Start/End cho Video."
                            : "Chế độ Sáng Tạo: Tạo ảnh nghệ thuật từ văn bản và ảnh tham chiếu."}
                    </p>
                </div>
            ) : (
                <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
                    {results.map((img) => (
                        <div key={img.id} className="group relative bg-zinc-900 rounded-xl overflow-hidden border border-zinc-800 shadow-md hover:border-zinc-600 transition-all">
                            {/* Image Thumbnail */}
                            <div className="aspect-video w-full overflow-hidden bg-black relative cursor-zoom-in" onClick={() => setSelectedImageId(img.id)}>
                                <img src={img.url} alt="Result" className="w-full h-full object-contain" />
                                <div className="absolute top-2 left-2 bg-black/60 text-white px-2 py-0.5 rounded text-[10px] backdrop-blur-md">
                                    {img.ratio}
                                </div>
                            </div>

                            {/* Info */}
                            <div className="p-3">
                                <p className="text-xs text-zinc-500 line-clamp-2 mb-2 h-8" title={img.prompt}>
                                    {img.prompt}
                                </p>
                                <div className="flex justify-between items-center">
                                     <span className="text-[10px] text-zinc-600 font-mono">{new Date(img.timestamp).toLocaleTimeString()}</span>
                                     <div className="flex items-center gap-1">
                                        <button 
                                            onClick={(e) => { e.stopPropagation(); handleDeleteImage(img.id); }}
                                            className="text-zinc-500 hover:text-red-500 p-1.5 rounded-md hover:bg-zinc-800 transition-colors"
                                            title="Xóa ảnh"
                                        >
                                            <Trash2 size={16} />
                                        </button>
                                        <a href={img.url} download={`img_${img.id}.png`} className="text-zinc-400 hover:text-white p-1.5 rounded-md hover:bg-zinc-800 transition-colors" onClick={(e) => e.stopPropagation()}>
                                            <Download size={16} />
                                        </a>
                                     </div>
                                </div>
                            </div>
                        </div>
                    ))}
                </div>
            )}
        </div>

      </main>

      {selectedImage && (
        <ImageViewer 
            image={selectedImage} 
            onClose={() => setSelectedImageId(null)}
            onNext={handleNext}
            onPrev={handlePrev}
            hasNext={selectedIndex < results.length - 1}
            hasPrev={selectedIndex > 0}
        />
      )}
    </div>
  );
}

import React, { useEffect, useState } from 'react';
import { ApiCredentials } from '../types';
import { Key, Server, LogIn, AlertTriangle, Globe, ShieldAlert, Wifi, Cloud, Clapperboard } from 'lucide-react';

interface ApiKeyModalProps {
  onCredentialsSubmit: (creds: ApiCredentials) => void;
}

// Các URL gợi ý dựa trên yêu cầu của bạn
const SUGGESTED_URLS = [
  { label: "Localhost (Máy cá nhân)", url: "http://127.0.0.1:8045/v1", icon: <Server size={12} /> },
  { label: "Mạng LAN (IP Tĩnh)", url: "http://192.168.1.22:8045/v1", icon: <Wifi size={12} /> },
  { label: "Public Tunnel (Cloudflare)", url: "https://improved-communication-transmit-retain.trycloudflare.com/v1", icon: <Cloud size={12} /> }
];

const ApiKeyModal: React.FC<ApiKeyModalProps> = ({ onCredentialsSubmit }) => {
  const [isOpen, setIsOpen] = useState(true);
  const [baseUrl, setBaseUrl] = useState('http://127.0.0.1:8045/v1');
  const [apiKey, setApiKey] = useState('sk-715c78c494c34e7493ff66af32cc7200');

  // Detection states
  const [isHttps, setIsHttps] = useState(false);
  const [isLocalhost, setIsLocalhost] = useState(false);
  const [logoError, setLogoError] = useState(false);

  useEffect(() => {
    setIsHttps(window.location.protocol === 'https:');

    const storedBaseUrl = localStorage.getItem('app_base_url');
    const storedApiKey = localStorage.getItem('app_api_key');

    if (storedBaseUrl) {
        setBaseUrl(storedBaseUrl);
        checkLocalhost(storedBaseUrl);
    }
    if (storedApiKey) setApiKey(storedApiKey);
    else checkLocalhost('http://127.0.0.1:8045/v1'); 
  }, []);

  const checkLocalhost = (url: string) => {
      const isLocal = url.includes('127.0.0.1') || url.includes('localhost') || url.startsWith('http://0.0.0.0') || url.startsWith('http://192.168.');
      setIsLocalhost(isLocal);
  };

  const handleBaseUrlChange = (e: React.ChangeEvent<HTMLInputElement>) => {
      const val = e.target.value;
      setBaseUrl(val);
      checkLocalhost(val);
  };

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (!baseUrl || !apiKey) {
        alert("Vui lòng nhập đầy đủ thông tin");
        return;
    }

    let formattedUrl = baseUrl;
    if (formattedUrl.endsWith('/')) {
        formattedUrl = formattedUrl.slice(0, -1);
    }

    localStorage.setItem('app_base_url', formattedUrl);
    localStorage.setItem('app_api_key', apiKey);

    onCredentialsSubmit({ baseUrl: formattedUrl, apiKey });
    setIsOpen(false);
  };

  if (!isOpen) return null;

  return (
    <div className="fixed inset-0 z-50 flex items-center justify-center bg-black/95 backdrop-blur-md px-4">
      <div className="bg-cinema-gray border border-zinc-700 p-8 rounded-xl max-w-lg w-full shadow-2xl relative overflow-hidden">

        <div className="text-center mb-6 relative z-10 flex flex-col items-center">
            {/* Logo Image with Fallback */}
            {logoError ? (
                <div className="w-16 h-16 rounded-xl bg-gradient-to-br from-cinema-accent to-rose-800 flex items-center justify-center shadow-2xl mb-4 border border-zinc-700">
                    <Clapperboard className="text-white" size={32} />
                </div>
            ) : (
                <img 
                    src="YFilm%20Google.png" 
                    alt="Logo" 
                    className="w-16 h-16 rounded-xl shadow-2xl mb-4 border border-zinc-700 object-cover" 
                    onError={() => setLogoError(true)}
                />
            )}
            <h2 className="text-2xl font-bold text-white">Kết Nối Đạo Diễn AI</h2>
            <p className="text-zinc-400 text-sm mt-2">Dùng API OpenAI (Google Banana Pro)</p>
        </div>

        <form onSubmit={handleSubmit} className="space-y-5 relative z-10">
            <div>
                <label className="block text-xs font-medium text-zinc-500 mb-2 flex items-center gap-2">
                    <Server size={14} /> Base URL (API Endpoint)
                </label>

                {/* Suggestions Chips */}
                <div className="flex flex-wrap gap-2 mb-3">
                    {SUGGESTED_URLS.map((opt) => (
                        <button
                            key={opt.url}
                            type="button"
                            onClick={() => { setBaseUrl(opt.url); checkLocalhost(opt.url); }}
                            className={`text-[10px] flex items-center gap-1.5 px-2 py-1.5 rounded border transition-colors ${baseUrl === opt.url ? 'bg-cinema-accent border-cinema-accent text-white' : 'bg-zinc-900 border-zinc-700 text-zinc-400 hover:border-zinc-500'}`}
                        >
                            {opt.icon} {opt.label}
                        </button>
                    ))}
                </div>

                <div className="relative">
                    <input 
                        type="text" 
                        value={baseUrl}
                        onChange={handleBaseUrlChange}
                        placeholder="Nhập Base URL..."
                        className={`w-full bg-zinc-900 border rounded-lg p-3 pl-10 text-sm text-white focus:outline-none transition-colors ${
                            isHttps && isLocalhost ? 'border-yellow-600 focus:border-yellow-500' : 'border-zinc-700 focus:border-cinema-accent'
                        }`}
                    />
                    <div className="absolute left-3 top-3 text-zinc-500">
                        {isLocalhost ? <ShieldAlert size={16} className={isHttps ? "text-yellow-500" : ""} /> : <Globe size={16} />}
                    </div>
                </div>
            </div>

            {/* Smart Warning for Mixed Content */}
            {isHttps && isLocalhost && (
                <div className="bg-yellow-900/20 border border-yellow-700/50 rounded-lg p-3 flex gap-3 items-start">
                    <AlertTriangle className="text-yellow-500 shrink-0 mt-0.5" size={18} />
                    <div className="text-xs text-zinc-300">
                        <strong className="text-yellow-500 block mb-1">Cảnh báo Mixed Content:</strong>
                        App đang chạy trên <strong>HTTPS</strong> nhưng API là <strong>HTTP</strong> (Localhost/LAN).
                        <ul className="list-disc list-inside mt-2 text-zinc-400 space-y-1">
                            <li>Khuyên dùng: Sử dụng <strong>Cloudflare Tunnel</strong> (https) để kết nối ổn định.</li>
                            <li>Hoặc: Chạy App này ở Localhost (http).</li>
                        </ul>
                    </div>
                </div>
            )}

            <div>
                <label className="block text-xs font-medium text-zinc-500 mb-1 flex items-center gap-2">
                    <Key size={14} /> API Key
                </label>
                <input 
                    type="password" 
                    value={apiKey}
                    onChange={(e) => setApiKey(e.target.value)}
                    placeholder="sk-..."
                    className="w-full bg-zinc-900 border border-zinc-700 rounded-lg p-3 text-sm text-white focus:border-cinema-accent focus:outline-none"
                />
            </div>

            <button
                type="submit"
                className="w-full bg-cinema-accent hover:bg-rose-700 text-white font-bold py-3 px-6 rounded-lg transition-all flex items-center justify-center gap-2 mt-4"
            >
                <LogIn size={18} />
                Kết nối Server
            </button>
        </form>

        <div className="mt-6 text-[10px] text-zinc-600 border-t border-zinc-800 pt-4 flex justify-between gap-4">
             <span>Gemini 3 Flash (Scripting/Reasoning)</span>
             <span>Gemini 3 Pro Image (Generation)</span>
        </div>
      </div>
    </div>
  );
};

export default ApiKeyModal;
